void euler(int v, vector<int> &res) {
  used[v] = true;
  for (; ptr[v] < (int)(g[v]).size();) {
    ++ptr[v];
    int u = g[v][ptr[v] - 1];
    euler(u, res);
    res.push_back(u);
  }
