  int m = 0;
  for (int i = 0; i < n; ++i) {
    if (a[i] == b[i]) {
      continue;
    }
    ++m;
    if (!mapa.count(b[i])) {
      mapa[b[i]] = k++;
    }
  }
  if (m > s) {
    cout << -1 << endl;
    return 0;
  }
  for (int i = 0; i < n; ++i) {
    if (a[i] == b[i]) {
      continue;
    }
    a[i] = mapa[a[i]];
    b[i] = mapa[b[i]];
    g[b[i]].push_back(a[i]);
    pos[{b[i], a[i]}].push_back(i);
  }
  vector<vector<int>> cycles;
  for (int i = 0; i < k; ++i) {
    if (!used[i]) {
      vector<int> arr;
      euler(i, arr);
      reverse((arr).begin(), (arr).end());
      cycles.push_back({});
      for (int i = 0; i < (int)(arr).size(); ++i) {
