        pos[{arr[i], arr[j]}].pop_back();
      }
    }
  }
  vector<vector<int>> res;
  if (s - m > 1 && (int)(cycles).size() > 1) {
    int len = min((int)(cycles).size(), s - m);
    res.push_back({});
    vector<int> newcycle;
    for (int i = (int)(cycles).size() - len; i < (int)(cycles).size(); ++i) {
