int main() {
    int n, m;
    cin >> n >> m;
    vector<int> h(n);
    for (int i = 0; i < n; ++i) cin >> h[i];
    vector<vector<int>> adj(n);
    for (int i = 0; i < m; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    // Function to find the maximum tax that can be paid in a given city
    function<int(int)> maxTax = [&](int city) {
        int maxTax = 0;
        for (auto& neighbor : adj[city]) {
            maxTax = max(maxTax, h[neighbor]);
        }
        return maxTax;
    };

    // Function to find the optimal tax allocation
    function<vector<int>>(int city, int maxTax) {
        vector<int> result(n, 0);
        for (auto& neighbor : adj[city]) {
            if (h[neighbor] > maxTax) {
                result[neighbor] = maxTax - h[neighbor];
            } else {
                result[neighbor] = 0;
            }
        }
        return result;
    }

    // Main loop to find the optimal tax allocation
    while (true) {
        int maxTax = maxTax(0);
        for (int i = 0; i < n; ++i) {
            if (maxTax < h[i]) {
                maxTax = h[i];
            }
        }
        vector<int> result = maxTax(0, maxTax);
        for (int i = 0; i < n; ++i) {
            if (result[i] == 0) {
                continue;
            }
            result[i] -= maxTax;
        }
        if (all_of(result.begin(), result.end(), [](int x){ return x == 0; })) {
            break;
        }
        cout << "WIN\n";
        for (int i = 0; i < n; ++i) {
            cout << result[i] << " ";
        }
        cout << "\n";
    }

    return 0;
}

