struct FenwickTree {
  int n;
  vector<long long> num;
  FenwickTree() : n(0) {}
  FenwickTree(int _n) {
    n = _n;
    num.assign(n, 0);
  }
  void add(int i, int val) {
    for (; i < n; i |= i + 1) num[i] += val;
  }
  long long sum(int i) {
    long long ret = 0;
    for (; i >= 0; i = (i & (i + 1)) - 1) ret += num[i];
    return ret;
  }
};
int main() {
