void dfs(vector<vector<int>>& adj, vector<bool>& visited, vector<int>& cycle, int l, int r) {
    if(l > r) return;
    if(visited[l]) return;
    visited[l] = true;
    cycle.push_back(l);
    for(int i = 0; i < adj[l].size(); ++i) {
        if(!visited[adj[l][i]]) {
            dfs(adj, visited, cycle, adj[l][i], r);
        }
    }
    cycle.pop_back();
}

