      xx = n - 1 + p.first;
      yy = n - 1 + p.second;
      if (good(xx, yy) and vect[xx][yy] == '0') ans1.push_back({xx, yy});
    }
    for (auto p : d4) {
      long long int xx, yy;
      xx = 0 + p.first;
      yy = 0 + p.second;
      if (good(xx, yy) and vect[xx][yy] == '0') ans2.push_back({xx, yy});
      xx = n - 1 + p.first;
      yy = n - 1 + p.second;
      if (good(xx, yy) and vect[xx][yy] == '1') ans2.push_back({xx, yy});
