  for (int(j) = 0; (j) < (int)(1 << logw); ++(j)) {
    for (int(i) = 0; (i) < (int)(1 << logh); ++(i)) tmp[i] = A[i][j];
    inverse_fft(logh, tmp.data());
    for (int(i) = 0; (i) < (int)(1 << logh); ++(i)) A[i][j] = tmp[i];
  }
  for (int(i) = 0; (i) < (int)(H); ++(i)) inverse_fft(logw, A[i].data());
}
