std::vector<std::string> isomorphicStrings(int N) {
    std::vector<std::string> result;
    for (int i = 1; i <= N; ++i) {
        std::string current = std::to_string(i);
        std::vector<int> count(26, 0);
        for (char c : current) {
            count[c - 'a']++;
        }
        if (count[0] != count[1]) {
            continue;
        }
        for (int j = 1; j < N; ++j) {
            std::string next = std::to_string(j + 1);
            std::vector<int> nextCount(26, 0);
            for (char c : next) {
                nextCount[c - 'a']++;
            }
            if (nextCount[0] != nextCount[1]) {
                continue;
            }
            if (current == next) {
                result.push_back(current);
            }
        }
    }
    return result;
}

