bool hasDent(const std::vector<double>& points) {
    int n = points.size();
    if (n < 4) return false;

    // Sort the points by their x-coordinates
    std::sort(points.begin(), points.end());

    // Check if any three consecutive points form a straight line
    for (int i = 0; i < n - 2; ++i) {
        if (points[i + 1] - points[i] == points[i + 2] - points[i]) {
            return true;
        }
    }

    return false;
}

