long long w[6 * 100055];
int edge;
inline void addEdge(int x, int y, long long z) {
  to[++edge] = y, w[edge] = z, nex[edge] = head[x], head[x] = edge;
  to[++edge] = x, w[edge] = z, nex[edge] = head[y], head[y] = edge;
}
