struct node {
  int x;
  long long val;
  node(int x, long long val) : x(x), val(val) {}
  friend bool operator<(node x1, node x2) { return x1.val > x2.val; }
};
priority_queue<node> que;
int pre[100055];
int findd(int x) {
  if (pre[x] == x) return x;
  return pre[x] = findd(pre[x]);
}
long long f[100055][18];
int g[100055][18];
int dep[100055];
int N;
void dfs(int u, int fa) {
  for (int i = 1; i <= N; i++) {
    g[u][i] = g[g[u][i - 1]][i - 1];
    f[u][i] = max(f[u][i - 1], f[g[u][i - 1]][i - 1]);
  }
  for (int i = head[u]; i; i = nex[i]) {
    int v = to[i];
    if (v == fa) continue;
    dep[v] = dep[u] + 1;
    g[v][0] = u;
    f[v][0] = w[i];
    dfs(v, u);
  }
}
inline long long lca(int x, int y) {
  if (dep[x] > dep[y]) swap(x, y);
  long long ans = 0;
  for (int i = N; i >= 0; i--) {
    if (dep[g[y][i]] >= dep[x]) {
      ans = max(ans, f[y][i]);
      y = g[y][i];
    }
  }
  if (x == y) return ans;
  for (int i = N; i >= 0; i--) {
    if (g[x][i] != g[y][i]) {
      ans = max(f[x][i], ans);
      ans = max(f[y][i], ans);
      x = g[x][i];
      y = g[y][i];
    }
  }
  if (x != y) ans = max(ans, f[x][0]), ans = max(ans, f[y][0]);
  return ans;
}
