  if (x == 1) {
    cout << 1 << '\n' << 0 << '\n';
  } else if (prim(x)) {
    cout << 1 << '\n';
    cout << 0 << '\n';
  } else {
    prime((int)sqrt(x));
    int res = 0, b = -1, up = -1;
    for (int i = 2; i * 1ll * i <= x; ++i) {
      if (!pr[i] && (x % (i * 1ll) == 0)) {
        res++;
        if (up == -1)
          up = i;
        else if (b == -1)
          b = i;
      }
      if (res >= 3) break;
    }
    if (res < 1) {
      cout << 2 << '\n';
    } else if (res == 1) {
      if (x % (up * up * 1ll) == 0 && (up * up) != x) {
        cout << 1 << '\n';
        cout << up * 1ll * up << '\n';
      } else {
        cout << 2 << '\n';
      }
    } else if (res == 2 && up * 1ll * b == x) {
      cout << 2 << '\n';
    } else {
      cout << 1 << '\n';
      cout << up * 1ll * b << '\n';
    }
  }
  return 0;
}

