    fill(a, a + LIM, 0);
    for (int i = 0; i < (int)s.length(); ++i) ++a[s[i] - 'a'];
  }
};
string sa, sb, sc;
int check(str& a, int cur, str& b, str& c) {
  int ans = INF;
  for (int i = 0; i < LIM; ++i) {
    if (a.a[i] < b.a[i] * cur)
      ans = -1;
    else if (c.a[i] != 0)
      ans = min(ans, (a.a[i] - cur * b.a[i]) / c.a[i]);
  }
  if (ans != -1) return ans + cur;
  return ans;
}
