  for (int i = 0; i < cur; ++i) cout << sb;
  int sec = check(a, cur, b, c) - cur;
  for (int i = 0; i < sec; ++i) cout << sc;
  for (int i = 0; i < LIM; ++i) {
    a.a[i] -= b.a[i] * cur;
    a.a[i] -= c.a[i] * sec;
