int f(char c) {
  switch (c) {
    case 'L':
      return 0;
    case 'R':
      return 1;
    case 'U':
      return 2;
    case 'D':
      return 3;
  }
}
int solve(int x) {
  for (int i = 0; i < mn; ++i) {
    p[i][0] = i % n == 0 ? -1 : i - 1;
    p[i][1] = i % n == n - 1 ? -1 : i + 1;
    p[i][2] = i - n;
    p[i][3] = i + n;
  }
  vw = x;
  int ret = 0;
  while (1) {
    ret++;
    v[x] = vw;
    int z = f(c[x]);
    int X = x;
    while (c[X] == '.' || v[X] == vw) {
      X = p[X][z];
      if (!(0 <= X && X < mn)) return ret;
    }
    p[x][z] = X;
    x = X;
  }
}
