void init() {
  ip = 0;
  memset(head, -1, sizeof(head));
}
void add(int u, int v) { tu[ip].to = v, tu[ip].next = head[u], head[u] = ip++; }
vector<int> scc[N];
stack<int> S;
void dfs(int u) {
  dfn[u] = low[u] = ++step;
  S.push(u);
  for (int i = head[u]; i != -1; i = tu[i].next) {
    int v = tu[i].to;
    if (!dfn[v]) {
      dfs(v);
      low[u] = min(low[u], low[v]);
    } else if (!sccno[v])
      low[u] = min(low[u], dfn[v]);
  }
  if (low[u] == dfn[u]) {
    scc_cnt += 1;
    scc[scc_cnt].clear();
    while (1) {
      int x = S.top();
      S.pop();
      if (sccno[x] != scc_cnt) scc[scc_cnt].push_back(x);
      sccno[x] = scc_cnt;
      if (x == u) break;
    }
  }
}
