using namespace std;

struct Robot {
    string nickname;
    vector<pair<int, int>> travelRoutes;
};

int main() {
    int N, T, R;
    cin >> N >> T >> R;

    vector<Robot> robots(N);
    for (int i = 0; i < N; ++i) {
        cin >> robots[i].nickname >> robots[i].travelRoutes[0].first >> robots[i].travelRoutes[0].second;
        for (int j = 1; j < robots[i].travelRoutes.size(); ++j) {
            robots[i].travelRoutes[j].first += robots[i].travelRoutes[j - 1].first;
            robots[i].travelRoutes[j].second += robots[i].travelRoutes[j - 1].second;
        }
    }

    unordered_map<string, int> robotPositions;
    for (const auto& robot : robots) {
        robotPositions[robot.nickname] = 0;
    }

    for (int t = 0; t < T; ++t) {
        for (const auto& robot : robots) {
            int nextPosition = robotPositions[robot.nickname];
            for (const auto& route : robot.travelRoutes) {
                int nextX = nextPosition + route.first;
                int nextY = nextPosition + route.second;
                if (nextX >= 0 && nextX < 500 && nextY >= 0 && nextY < 500) {
                    robotPositions[robot.nickname]++;
                }
            }
        }
    }

    for (const auto& pair : robotPositions) {
        cout << pair.first << endl;
    }

    return 0;
}

