#include <iostream>
using namespace std;

int main() {
    int r, c, a1, a2, b1, b2;
    cin >> r >> c >> a1 >> a2 >> b1 >> b2;

    // Initialize a 2D array to store the minimum cost to reach each cell
    vector<vector<int>> dp(r, vector<int>(c, INT_MAX));

    // Base case: cost to reach the starting cell is 0
    dp[a1][a2] = 0;

    // Fill the dp array using dynamic programming
    for (int i = 0; i < r; ++i) {
        for (int j = 0; j < c; ++j) {
            // Check all possible moves
            if (i > 0) {
                dp[i][j] = min(dp[i][j], dp[i - 1][j] + 1);
            }
            if (j > 0) {
                dp[i][j] = min(dp[i][j], dp[i][j - 1] + 1);
            }
            if (i < r - 1) {
                dp[i][j] = min(dp[i][j], dp[i + 1][j] + 1);
            }
            if (j < c - 1) {
                dp[i][j] = min(dp[i][j], dp[i][j + 1] + 1);
            }
        }
    }

    // Output the result
    cout << dp[a1][a2] % 100000007 << endl;

    return 0;
}

