int getdir(char c){
	switch(c){
		case 'R': return 0;
		case 'U': return 1;
		case 'L': return 2;
		case 'D': return 3;
	}
	abort();
}

struct solver{
	int n;
	solver(int n_) : n(n_) {}
	vector<vint> ids[9];
	vint trs[4];
	vint unit;
	const char *p;

	vint mul(const vint &x, const vint &y){
		int sz = x.size();
		vint ret(sz);
		REP(i, sz){ ret[i] = y[x[i]]; }
		return ret;
	}

	vint pow(vint x, LL y){
		vint a = unit;
		while(y){
			if(y & 1){ a = mul(a, x); }
			x = mul(x, x);
			y >>= 1;
		}
		return a;
	}

	vint parse(){
		vint a = unit;
		vint b;
		while(1){
			if(*p == '('){
				++p;
				vint x = parse();
				++p;
				char *endp;
				LL r = strtoll(p, &endp, 10);
				p = endp;
				b = pow(x, r);
			}
			else if(isalpha(*p)){
				int dir = getdir(*p);
				++p;
				b = trs[dir];
			}
			else{ break; }
			a = mul(a, b);
		}
		return a;
	}

	void solve(){
		vector<string> in0(n);
		REP(i, n){ cin >> in0[i]; }
		string op;
		cin >> op;

		int fstdir = -1;
		for(char c : op){
			if(isalpha(c)){
				fstdir = getdir(c);
				break;
			}
		}

		vector<string> in(n, string(n, '.'));
		if(fstdir == 0){
			REP(y, n){
				int u = n - 1;
				RREP(x, n){
					if(in0[y][x] != '.'){
						in[y][u--] = in0[y][x];
					}
				}
			}
		}
		else if(fstdir == 1){
			REP(x, n){
				int u = 0;
				REP(y, n){
					if(in0[y][x] != '.'){
						in[u++][x] = in0[y][x];
					}
				}
