        vector<vector<double> > dp(n+1, vector<double>(m+1, INF));
        dp[0][0] = 0.0;
        for(int i=0; i<n; ++i){
            for(int j=0; j<m; ++j){
                for(int k=i+1; k<n; ++k){
                    dp[k+1][j+1] = min(dp[k+1][j+1], dp[i][j] + error[i][k]);
                }
            }
        }

        printf("%.10f\n", dp[n][m]);
    }
}

