double calculateProbability(const std::string& input) {
    std::istringstream iss(input);
    int H, W;
    iss >> H >> W;

    // Read the masses of type A, B, and X
    double mA1, mA2, mB1, mB2, mX;
    iss >> mA1 >> mA2 >> mB1 >> mB2 >> mX;

    // Read the matrix
    std::vector<std::vector<char>> matrix(H, std::vector<char>(W));
    for (int i = 0; i < H; ++i) {
        for (int j = 0; j < W; ++j) {
            iss >> matrix[i][j];
        }
    }

    // Calculate the total mass of the matrix
    double totalMass = 0;
    for (int i = 0; i < H; ++i) {
        for (int j = 0; j < W; ++j) {
            totalMass += matrix[i][j];
        }
    }

    // Calculate the probability that the center of gravity is on the object
    double probability = 0.0;
    for (int i = 0; i < H; ++i) {
        for (int j = 0; j < W; ++j) {
            if (matrix[i][j] == 'A') {
                probability += std::pow((i + j) / 2.0, 2);
            } else if (matrix[i][j] == 'B') {
                probability += std::pow((i + j) / 2.0, 2);
            } else if (matrix[i][j] == 'X') {
                probability += std::pow((i + j) / 2.0, 2);
            }
        }
    }

    return probability;
}

