bool isConvex(const std::vector<std::pair<int, int>>& points) {
    int n = points.size();
    for (int i = 0; i < n; ++i) {
        if (points[i].first == points[(i + 1) % n].first && points[i].second == points[(i + 1) % n].second) {
            return false;
        }
        if (points[i].first == points[(i + 1) % n].first || points[i].second == points[(i + 1) % n].second) {
            return false;
        }
    }
    return true;
}

