using namespace std;

int minOperations(vector<int>& a, int s) {
    sort(a.begin(), a.end());
    int n = a.size();
    int left = 0;
    int right = n - 1;
    int count = 0;

    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (a[mid] == s) {
            return count;
        } else if (a[mid] < s) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
        count++;
    }

    return count;
}

