bool Comp(const an &a, const an &b) { return a.val > b.val; }
void Solve() {
  sort(d[0].begin(), d[0].end(), Comp);
  sort(d[1].begin(), d[1].end(), Comp);
  sort(d[2].begin(), d[2].end(), Comp);
  int ans[3];
