    }
    for (int i = 0; i < 3; i++) {
      cout << l[ans[i]].name << ' ';
      cout << ans_out[i].size() << ' ';
      for (int j = 0; j < ans_out[i].size(); j++) cout << ans_out[i][j] << ' ';
      cout << endl;
    }
  }
