int findSmallestX(int n, int m, std::vector<int>& a, std::vector<int>& b) {
    // Sort the arrays
    std::sort(a.begin(), a.end());
    std::sort(b.begin(), b.end());

    // Find the minimum difference between any two elements in a and b
    int minDiff = std::numeric_limits<int>::max();
    for (int i = 0; i < n; ++i) {
        minDiff = std::min(minDiff, abs(a[i] - b[i]));
    }

    // Calculate the smallest non-negative integer x
    return m - minDiff;
}

