long long bigmod(long long n, long long p) {
  if (p == 0) return 1;
  long long x = bigmod(n, p / 2) % mod;
  x = (x * x) % mod;
  if (p % 2) x = (x * n) % mod;
  return x;
}
long long ncr(long long n, long long r) {
  if (r > n) return 0;
  long long res = fac[n] % mod;
  res = (res * inv[n - r]) % mod;
  res = (res * inv[r]) % mod;
  return res;
}
