long long modexp(long long a, long long n) {
  long long res = 1;
  while (n) {
    if (n & 1) res = ((res % 1000000007) * (a % 1000000007)) % 1000000007;
    a = ((a % 1000000007) * (a % 1000000007)) % 1000000007;
    n >>= 1;
  }
  return res;
}
