int mejor(multiset<int> &s, int precio) {
  auto it = s.upper_bound(precio / 2);
  int ans = precio;
  if (it != s.end()) {
    ans = min(ans, max(precio - *it, *it));
  }
  if (it != s.begin()) {
    it--;
    ans = min(ans, max(precio - *it, *it));
  }
  return ans;
}
