    std::string message;
    for (int i = 0; i < n; ++i) {
        std::cin >> orders[i];
        std::cin >> message;
    }

    std::string inferredMessage = inferMessage(orders, message);
    std::cout << inferredMessage << std::endl;

    return 0;
}

