            if (_s[_ix] == '!') {
                _ix += 2;
                pos = _ix;
                rev.push_back(true);
            }
            else {
                _ix += 1;
                pos = _ix;
                rev.push_back(false);
            }
        }
        else {
            _ix++;
        }
    }
    string val = _s.substr(pos, _ix-pos);
    bool cur = val == "true";
    vector<pair<vector<string>, bool> > rs;
    for (int i = (int)props.size()-1; i >= 0; i--) {
        if (rev[i]) cur = !cur;
//        cerr << props[i] << " = " << cur << endl;
        rs.push_back(make_pair(parse_prop(props[i]), cur));
    }
    _ix++;
    return rs;
}

pair<string, Fun*> parse_fun() {
