    for (int j = 1; j <= t; j++) {
      mr2[i][j] = -1;
      for (int k = 0; k < j; k++) {
        if (mr2[i][k] == -1) continue;
        if (!cl2[i - 1][j - k]) continue;
        long long mn = mr2[i][k] % z, mx = mr2[i][k];
        long long rm =
            mn + pb[i] * (j - k) - (pb[i - 1] * (j - k) + z - 1) / z * z;
        mn += (j - k) * b[i];
        mx += (j - k) * b[i];
        if (rm < 0) mn += z, rm += z;
        if (mn > mx) continue;
        if (mn > c[i]) continue;
        if (mx > c[i]) {
          long long f = mx - c[i];
          f = (f + z - 1) / z;
          mx -= f * z;
        }
        mx = mx - mn + rm;
        mn = rm;
        mr2[i][j] = max(mr2[i][j], mx);
