          long long rm =
              pa[i] + pb[i] * j - (pa[i - 1] + pb[i - 1] * j + z - 1) / z * z;
          if (rm >= 0) mr1[i][j] = rm;
        }
      }
      for (int k = 0; k < j; k++) {
        if (mr1[i][k] == -1) continue;
        if (!cl2[i - 1][j - k]) continue;
        long long mn = mr1[i][k] % z, mx = mr1[i][k];
        long long rm =
            mn + pb[i] * (j - k) - (pb[i - 1] * (j - k) + z - 1) / z * z;
        mn += (j - k) * b[i];
        mx += (j - k) * b[i];
        if (rm < 0) mn += z, rm += z;
        if (mn > mx) continue;
        if (mn > c[i]) continue;
        if (mx > c[i]) {
          long long f = mx - c[i];
          f = (f + z - 1) / z;
          mx -= f * z;
        }
        mx = mx - mn + rm;
        mn = rm;
        mr1[i][j] = max(mr1[i][j], mx);
      }
    }
    for (int j = 0; j <= t; j++) {
      if (cl1[i - 1][j]) {
        if (a[i] + b[i] * j <= c[i]) cl1[i][j] = true;
      }
      for (int k = 0; k < j; k++) {
        if (mr1[i][k] == -1) continue;
        if (!cl2[i - 1][j - k]) continue;
        if (mr1[i][k] % z + (j - k) * b[i] <= c[i]) cl1[i][j] = true;
      }
    }
  }
  for (int i = 1; i <= n; i++) {
    for (int j = 1; j <= t; j++) {
      dp2[i][j] = 1e18;
