      }
      for (int k = 1; k <= j; k++) {
        if (cl2[i][k]) {
          long long cost = (pb[i] * k + z - 1) / z;
          dp2[i][j] = min(dp2[i][j], dp2[i][j - k] + cost);
        }
      }
      for (int k = 1; k <= j; k++) {
        if (mr2[i][k] != -1) {
          if (mr2[i][k] % z + (j - k) * b[i] > c[i]) continue;
          long long cost = (pb[i] * k - mr2[i][k]) / z;
          long long f = mr2[i][k] + (j - k) * b[i] - c[i];
          if (f > 0) {
            cost += (f + z - 1) / z;
          }
          dp2[i][j] = min(dp2[i][j], dp2[i - 1][j - k] + cost);
        }
      }
