const int INF = 1e9 + 7, M = 998244353, N = 1e5 + 7;
int f[N], inv[N], fi[N];
int INV(int i) {
  if (i == 1) return 1;
  return M - (long long)M / i * INV(M % i) % M;
}
int C(int n, int k) { return (long long)f[n] * fi[k] % M * fi[n - k] % M; }
int H(int n, int k) {
  if (n == 0) return k == 0;
  return C(n + k - 1, k);
}
void add(int& a, int b) {
  a += b;
  if (a >= M) a -= M;
}
signed main() {
  std::ios::sync_with_stdio(0);
  std::cin.tie(0);
