void trial(long long n) {
  int count;
  long long ini = n;
  for (long long d = 2; d * d <= n; d++) {
    if (n % d == 0) {
      ini = n;
      while (n % d == 0) {
        n /= d;
      }
      long long s = ini / n;
      factors.push_back(s);
    }
  }
  if (n > 1) {
    factors.push_back(n);
  }
}
