long long lca(long long x, long long y) {
  if (x == y) return 0;
  if (lvl[x] < lvl[y]) swap(x, y);
  long long d = lvl[x] - lvl[y];
  long long x1 = x;
  for (long long i = (0); i <= (20); i++)
    if ((1 << i) & d) x1 = dp[x1][i];
  if (x1 == y) return d;
  long long xx = x1, yy = y;
  for (long long i = (20); i >= (0); i--)
    if (dp[xx][i] != dp[yy][i]) {
      d += 2 * (1 << i);
      xx = dp[xx][i];
      yy = dp[yy][i];
    }
  d += 2;
  return d;
}
