#include <algorithm>

std::string findLexicographicallySmaller(const std::string& s, const std::string& t) {
    // Create a vector of characters from the string s
    std::vector<char> charVector(s.begin(), s.end());

    // Sort the vector in lexicographical order
    std::sort(charVector.begin(), charVector.end());

    // Find the index of the first character that is smaller than the target character t
    int index = std::find(charVector.begin(), charVector.end(), t[0]);

    // If the target character t is not found, return -1
    if (index == charVector.end()) {
        return "-1";
    }

    // Swap the character at the found index with the target character t
    std::swap(charVector[index], t[0]);

    // Convert the sorted vector back to a string
    std::string result;
    for (char c : charVector) {
        result += c;
    }

    return result;
}

int main() {
    std::string s, t;

    // Read the input strings
    std::cin >> s >> t;

    // Find the lexicographically smaller string
    std::string result = findLexicographicallySmaller(s, t);

    // Output the result
    std::cout << result << std::endl;

    return 0;
}

