pos segIntSeg(seg a, seg b) {
  double t =
      cross(fwd(a.a, b.a), fwd(a.a, a.b)) / cross(fwd(a.a, a.b), fwd(b.a, b.b));
  return b.a + fwd(b.a, b.b) * t;
}
