int memo[N][30];
int solve(int x, int c) {
  int j = 0, miss = 0, ret = 0;
  for (int i = 1; i <= n; i++) {
    if (a[i] != c && j < i) miss++, j = i;
    while (j + 1 <= n && (a[j + 1] == c || miss + 1 <= x)) {
      j++;
      if (a[j] != c) miss++;
    }
    if (miss <= x) ret = max(ret, j - i + 1);
    if (a[i] != c) miss--;
  }
  return ret;
}
