    char ch[2];
    scanf("%d %s", &x, ch);
    c = (int)(ch[0] - 'a');
    if (memo[x][c] == -1) memo[x][c] = solve(x, c);
    printf("%d\n", memo[x][c]);
  }
  return 0;
}

