#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

std::string findPath(int n, int m, int k, std::vector<std::string>& map) {
    // Initialize the grid with 'S' and 'T'
    std::vector<std::string> grid(n, std::string(m, 'S'));
    grid[n - 1][m - 1] = 'T';

    // Function to check if a path is valid
    bool isValidPath(const std::vector<std::string>& grid, int x, int y, int k) {
        int dx[] = {0, 1, 0, -1};
        int dy[] = {1, 0, -1, 0};

        for (int i = 0; i < k; ++i) {
            int nx = x + dx[i];
            int ny = y + dy[i];

            if (nx >= 0 && nx < n && ny >= 0 && ny < m && grid[nx][ny] == 'S') {
                return false;
            }
        }

        return true;
    }

    // Function to find the lexicographically minimal path
    std::string findLexicographicallyMinimalPath(const std::vector<std::string>& grid, int x, int y, int k) {
        std::vector<std::string> path;
        std::vector<bool> visited(k, false);

        while (!isValidPath(grid, x, y, k)) {
            path.push_back(grid[x][y]);
            visited[y] = true;

            int nx = x + dx[k - 1];
            int ny = y + dy[k - 1];

            if (nx >= 0 && nx < n && ny >= 0 && ny < m && !visited[ny]) {
                x = nx;
                y = ny;
            } else {
                --k;
                if (k == 0) {
                    return "-1";
                }
            }
        }

        std::reverse(path.begin(), path.end());
        return path[0];
    }

    // Read the map
    for (int i = 0; i < n; ++i) {
        std::string row;
        std::cin >> row;
        for (char c : row) {
            grid[i][c - 'a'] = c;
        }
    }

    // Find the path from S to T
    std::string result = findLexicographicallyMinimalPath(grid, 0, 0, k);

    // Output the result
    std::cout << result << std::endl;
    return result;
}

#include <bits/stdc++.h>
using namespace std;
struct Node {
  int cnt = 1, key, prior;
  long long sum[5] = {};
  Node *left = NULL, *right = NULL;
};
typedef Node *PNode;
Node nodes[111111];
int pri[111111];
int nodeCount = 0;
inline int cnt(PNode &v) { return v ? v->cnt : 0; }
inline void update(PNode &v) {
  if (v) {
    v->cnt = cnt(v->left) + cnt(v->right) + 1;
    int off = 0;
    if (v->left) {
      for (int i = 0; i < (int)(5); ++i) v->sum[i] = v->left->sum[i];
      off = v->left->cnt % 5;
    } else {
      for (int i = 0; i < (int)(5); ++i) v->sum[i] = 0;
    }
    v->sum[off] += v->key;
    if (++off == 5) off = 0;
    if (v->right) {
      for (int i = 0; i < (int)(5); ++i) {
        int ii = i + off;
        if (ii >= 5) ii -= 5;
        v->sum[ii] += v->right->sum[i];
      }
    }
  }
}
void merge(PNode l, PNode r, PNode &t) {
  if (!l || !r) {
    t = l ? l : r;
    return;
  }
  if (l->prior > r->prior) {
    merge(l->right, r, l->right);
    t = l;
  } else {
    merge(l, r->left, r->left);
    t = r;
  }
  update(t);
}
void split(PNode t, PNode &l, PNode &r, int key) {
  if (!t) {
    l = r = NULL;
    return;
  }
  if (key < t->key) {
    split(t->left, l, t->left, key);
    r = t;
  } else {
    split(t->right, t->right, r, key);
    l = t;
  }
  update(t);
}
PNode root = NULL;
void addKey(int x) {
  PNode t1, t2, t3;
  split(root, t1, t3, x);
  nodes[nodeCount].key = x;
  nodes[nodeCount].prior = pri[nodeCount];
  t2 = nodes + nodeCount++;
  update(t2);
  merge(t1, t2, root);
  merge(root, t3, root);
}
void delKey(PNode &t, int x) {
  if (t->key == x) {
    merge(t->left, t->right, t);
  } else if (x < t->key) {
    delKey(t->left, x);
  } else {
    delKey(t->right, x);
  }
  update(t);
}
mt19937 mt;
int myRand(int bound) { return mt() % bound; }
char s[10];
int zzz;
int main() {
  for (int i = 0; i < (int)(111111); ++i) pri[i] = i;
  random_shuffle(pri, pri + 111111, myRand);
  int q;
  scanf("%d", &q);
  for (int query = 0; query < (int)(q); ++query) {
    scanf("%s", s);
    if (s[0] == 'a') {
      scanf("%d", &zzz);
      addKey(zzz);
    } else if (s[0] == 'd') {
      scanf("%d", &zzz);
      delKey(root, zzz);
    } else {
      if (root == NULL) {
        printf("0\n");
      } else {
