#include <algorithm>

int minMeetingTime(int K, int N, std::vector<int>& t) {
    // Sort the times to ensure the meetings are in order
    std::sort(t.begin(), t.end());

    int totalTime = 0;
    int currentTime = 0;

    for (int i = 0; i < N; ++i) {
        // If the current time is less than or equal to the next time, add the time to the total
        if (currentTime <= t[i]) {
            totalTime += t[i];
            currentTime = t[i] + 1;
        }
    }

    return totalTime;
}

int main() {
    int K, N;
    std::cin >> K >> N;

    std::vector<int> t(N);
    for (int i = 0; i < N; ++i) {
        std::cin >> t[i];
    }

    int result = minMeetingTime(K, N, t);
    std::cout << result << std::endl;

    return 0;
}

