vector<Rect> simulate(const vector<Rect> &rects, int dir, ll l, ll u, int index) {
  int cnt = 0;
  vector<Rect> ret;
  vector<int> ds;
  if (dir != 0) {
    ds.push_back(dir);
    ret.resize(rects.size());
  } else {
    ds.push_back(1);
    ds.push_back(-1);
    ret.resize(rects.size() * 2);
  }
  FORIT(it1, ds) {
    int d = *it1;
    FORIT(it2, rects) {
      Rect r = *it2;
      r.Move(d, l, u, index);
      ret[cnt++] = r;
    }
  }
  return ret;
}

SegmentTree stree;
ll IntersectRect(vector<Rect> &rs1, vector<Rect> &rs2, bool swapxy) {
  if (rs1.size() == 0 || rs2.size() == 0) { return -1; }
  vector<Rect> *rss[2] = { &rs1, &rs2 };
  {
    map<ll, int> ys;
    REP(iter, 2) {
      // cout << iter << endl;
      FORIT(it, *rss[iter]) {
        if (swapxy) {
          swap(it->x1, it->y1);
          swap(it->x2, it->y2);
        }
        // cout << *it << endl;
        ys[it->y1] = 0;
        ys[it->y2] = 0;
      }
    }
    int index = 0;
    FORIT(it, ys) {
      it->second = index++;
    }
    // cout << index << endl;
    REP(iter, 2) {
      FORIT(it, *rss[iter]) {
        it->y1 = ys[it->y1];
        it->y2 = ys[it->y2];
      }
    }
  }
  // cout << rs1.size() << " " << rs2.size() << endl;
  REP(iter, 2) {
    stree = SegmentTree();
    vector<Event> events;
    FORIT(it, *rss[0]) {
      events.push_back(Event(-1, 1, it->x1, it->y1, it->y2));
      events.push_back(Event(-1, -1, it->x2 + 1, it->y1, it->y2));
    }
    int cnt = 0;
    FORIT(it, *rss[1]) {
      events.push_back(Event(cnt, 2, it->x1, it->y1, it->y2));
      events.push_back(Event(cnt, 2, it->x2, it->y1, it->y2));
      cnt++;
    }
    sort(events.begin(), events.end());
    // cout << "Start" << endl;
    FORIT(it, events) {
      Event e = *it;
      // cout << e.x << " " << e.y1 << " " << e.y2 << " " << e.inout << endl;
      if (e.index == -1) {
        stree.change(e.y1, e.y2, e.inout);
      } else {
        // cout << stree.get(e.y1, e.y2) << endl;
        if (stree.get(e.y1, e.y2) > 0) {
          Rect rect2 = (*rss[1])[e.index];
          REP(i, rss[0]->size()) {
            if (Hit((*rss[0])[i], rect2)) {
              // cout << (*rss[0])[i].dirs << endl;
              // cout << rect2.dirs << endl;
              return (*rss[0])[i].dirs | rect2.dirs;
            }
          }
          assert(false);
        }
      }
    }
    swap(rss[0], rss[1]);
  }
  return -1;
}
ll IntersectRect2(vector<Rect> &rs1, vector<Rect> &rs2, bool swapxy) {
  if (rs1.size() == 0 || rs2.size() == 0) { return -1; }
  vector<Rect> *rss[2] = { &rs1, &rs2 };
  {
    REP(iter, 2) {
      // cout << iter << endl;
      FORIT(it, *rss[iter]) {
        if (swapxy) {
          swap(it->x1, it->y1);
          swap(it->x2, it->y2);
        }
      }
    }
  }
  // cout << rs1.size() << " " << rs2.size() << endl;
  REP(iter, 2) {
    vector<Event> events;
    FORIT(it, *rss[0]) {
      events.push_back(Event(-1, 1, it->x1, it->y1, it->y2));
      events.push_back(Event(-1, -1, it->x2 + 1, it->y1, it->y2));
    }
    int cnt = 0;
    FORIT(it, *rss[1]) {
      events.push_back(Event(cnt, 2, it->x1, it->y1, it->y2));
      events.push_back(Event(cnt, 2, it->x2, it->y1, it->y2));
      cnt++;
    }
    sort(events.begin(), events.end());
    int hit = 0;
    // cout << "Start" << endl;
    FORIT(it, events) {
      Event e = *it;
      // cout << e.x << " " << e.y1 << " " << e.y2 << " " << e.inout << endl;
      if (e.index == -1) {
        hit += e.inout;
        assert(hit >= 0);
      } else {
        // cout << stree.get(e.y1, e.y2) << endl;
        if (hit > 0) {
          Rect rect2 = (*rss[1])[e.index];
          REP(i, rss[0]->size()) {
            if (Hit((*rss[0])[i], rect2)) {
              // cout << (*rss[0])[i].dirs << endl;
              // cout << rect2.dirs << endl;
              return (*rss[0])[i].dirs | rect2.dirs;
            }
          }
          assert(false);
        }
      }
    }
    swap(rss[0], rss[1]);
  }
  return -1;
}

int GetSolvingDir(int depth, int xy, ll flags) {
  if (dirs[depth] != 0) { return -999; }
  if (dirs[depth] == 0 && dirs[depth + 1] == 0) {
    if (xy == depth % 2) { return -1; } // both
    return 0; // tekitou
  }
  return (flags >> depth) & 1;
}
vector<Rect> simulate2(const vector<Rect> &rects, int pm, ll l, ll u, int index) {
  int cnt = 0;
  vector<Rect> ret;
  vector<int> pms;
  if (pm >= 0) {
    pms.push_back(pm);
    ret.resize(rects.size());
  } else {
    pms.push_back(0);
    pms.push_back(1);
    ret.resize(rects.size() * 2);
  }
  FORIT(it1, pms) {
    int v = *it1;
    FORIT(it2, rects) {
      Rect r = *it2;
      r.Move2(v, l, u, index);
      ret[cnt++] = r;
    }
  }
  return ret;
}
ll Solve(ll flags) {
  ll ans_flags[2] = { -1, -1 };
  REP(xy, 2) {
    int center = n;
    // both side search
    vector<Rect> rect1;
    rect1.push_back(Rect(0, 0, 0, 0, 0));
    REP(i, n) {
      int pm = GetSolvingDir(i, xy, flags);
      ll l = lower[i];
      ll u = upper[i];
      if (xy != i % 2) { l = 0; u = 0; }
      if (dirs[i] != 0) {
        rect1 = simulate(rect1, dirs[i], l, u, i);
      } else {
        // cout << "PM: " << pm << endl;
        rect1 = simulate2(rect1, pm, l, u, i);
      }
      if (rect1.size() > (1LL << 7)) {
        center = i + 1;
        break;
      }
    }
    vector<Rect> rect2;
    int left_upper = center % 2;
    rect2.push_back(Rect(left_upper, 0, 0, 0, 0));
    rect2.push_back(Rect(left_upper + 2, 0, 0, 0, 0));
    FOR(i, center, n) {
      int pm = GetSolvingDir(i, xy, flags);
      ll l = lower[i];
      ll u = upper[i];
      if (xy != i % 2) { l = 0; u = 0; }
      if (dirs[i] != 0) {
        rect2 = simulate(rect2, dirs[i], l, u, i);
      } else {
        rect2 = simulate2(rect2, pm, l, u, i);
      }
    }
    ll lx = xy == 0 ? 0 : X;
    ll ly = xy == 0 ? Y : 0;
    Mirror(rect2, left_upper, lx, ly);
    // cout << rect1.size() << " " << rect2.size() << endl;

    vector<Rect> rs1[4];
    vector<Rect> rs2[4];
    if (center != n && dirs[center] == 0 && dirs[center + 1] != 0) {
      // ignore connecting direction
      FORIT(it, rect1) {
        rs1[0].push_back(*it);
      }
      FORIT(it, rect2) {
        rs2[0].push_back(*it);
      }
    } else {
      FORIT(it, rect1) {
        rs1[it->dir].push_back(*it);
      }
      FORIT(it, rect2) {
        rs2[it->dir].push_back(*it);
      }
    }
    // cout << "test A" << endl;
    // FORIT(it, rect1) {
    //   cout << *it << " " << it->dir << endl;
    // }
    // cout << "test B" << endl;
    // FORIT(it, rect2) {
    //   cout << *it << " " << it->dir << endl;
    // }
    ll ans_dir_flags = -1;
    // cout << rect1.size() << " "<< rect2.size() << endl;
    // cout << xy << endl;
    REP(dir, 4) {
      // ans_dir_flags = IntersectRect(rs1[dir], rs2[dir], xy ^ 1);
      ans_dir_flags = IntersectRect2(rs1[dir], rs2[dir], xy ^ 1);
      if (ans_dir_flags != -1) { break; }
    }
    if (ans_dir_flags == -1) { return -1; }
    ans_flags[xy] = ans_dir_flags;
  }
  int dir = 0;
  REP(depth, n) {
    if (dirs[depth] != 0) {
      ans_dirs[depth] = dirs[depth];
    } else {
      int xy = depth % 2;
      ll v = (ans_flags[xy] >> depth) & 1;
      int ds[2] = { -1, 1 };
      REP(i, 2) {
        int ndir = (dir + ds[i] + 4) % 4;
        if ((v == 0 && ndir >= 2) ||
            (v == 1 && ndir <= 1)) {
          // set flag direction
          ans_dirs[depth] = ds[i];
        }
      }
    }
    dir = (dir + ans_dirs[depth] + 4) % 4;
  }
  // REP(i, n) {
  //   cout << (ans_dirs[i] == 1 ? "L" : "R");
  // }
  // cout << endl;
  return 1;
}

ll Dfs(int depth, ll flags) {
  if (depth == n) {
    return Solve(flags);
  }
  if (dirs[depth] == 0 && dirs[depth + 1] != 0) {
    assert(dirs[depth] == 0);
    REP(iter, 2) {
      ll nflags = flags | ((ll)iter << depth);
      if (Dfs(depth + 1, nflags) != -1) { return 1; }
    }
    return -1;
  }
  return Dfs(depth + 1, flags);
}

void RestoreDistance() {
  Rect r(0, 0, 0, 0, 0);
  {
    vector<Rect> rects(1, r);
    REP(i, n) {
      rects = simulate(rects, ans_dirs[i], lower[i], upper[i], i);
    }
    Rect rect = rects[0];
    // cout << rect << endl;
    // cout << X << " " << Y << endl;
    assert(Hit(Rect(0, X, Y, X, Y), rect));
  }
  REP(i, n) {
    int ndir = (r.dir + ans_dirs[i] + 4) % 4;
    ll l = lower[i];
    ll u = upper[i];
    while (l != u) {
      ll m = (l + u) / 2;
      assert(l < u);
      vector<Rect> rects(1, r);
      rects = simulate(rects, ans_dirs[i], m, m, i);
      FOR(j, i + 1, n) {
        rects = simulate(rects, ans_dirs[j], lower[j], upper[j], j);
      }
      Rect rect = rects[0];
      // cout << ndir << " " << rect << " "<< Y << endl;
      if ((ndir == 0 && rect.x2 < X) ||
          (ndir == 1 && rect.y2 < Y) ||
          (ndir == 2 && X < rect.x1) ||
          (ndir == 3 && Y < rect.y1)) {
        l = m + 1;
      } else {
        // cout << i << "  "<< "test" << endl;
        u = m;
      }
    }
    ans_l[i] = l;
    r.Move(ans_dirs[i], l, l, i);
  }
}

bool Check() {
  vector<Rect> rect(1, Rect(0, 0, 0, 0, 0));
  REP(i, n) {
    if (ans_l[i] < lower[i] || upper[i] < ans_l[i]) { return false; }
    if (dirs[i] != 0 && dirs[i] != ans_dirs[i]) { return false; }
    rect = simulate(rect, ans_dirs[i], ans_l[i], ans_l[i], i);
  }
  // cout << rect[0] << endl;
  // cout << X << " " << Y << endl;
  if (rect[0].x1 != X || rect[0].y1 != Y) { return false; }
  return true;
}

int main() {
  while (scanf("%d %lld %lld", &n, &X, &Y) > 0) {
    int center = n;
    int div = 0;
    REP(i, n) {
      char c;
      int v = scanf(" %c %lld %lld", &c, &lower[i], &upper[i]);
      assert(v == 3);
      if (c == 'L') { dirs[i] = 1; }
      if (c == '?') { dirs[i] = 0; }
      if (c == 'R') { dirs[i] = -1; }
      if (dirs[i] == 0) {
        div++;
        if (div == 21) { center = i; }
      }
    }
    dirs[n] = 0;
    int segment = 0;
    REP(i, n) { if (dirs[i] == 0 && dirs[i + 1] != 0) { segment++; } }
    ll ans_dir = -1;
    // cout << segment << " " << n << " " << n / 4 << endl;
    if (segment > n / 4 + 1) {
      // both side search
      // cout << "Normal" << endl;
      vector<Rect> rect1;
      rect1.push_back(Rect(0, 0, 0, 0, 0));
      REP(i, center) {
        rect1 = simulate(rect1, dirs[i], lower[i], upper[i], i);
      }
      vector<Rect> rect2;
      int left_upper = center % 2;
      rect2.push_back(Rect(left_upper, 0, 0, 0, 0));
      rect2.push_back(Rect(left_upper + 2, 0, 0, 0, 0));
      FOR(i, center, n) {
        rect2 = simulate(rect2, dirs[i], lower[i], upper[i], i);
      }
      // cout << rect1.size() << " " << rect2.size() << endl;
      Mirror(rect2, left_upper, X, Y);

      vector<Rect> rs1[4];
      FORIT(it, rect1) {
        rs1[it->dir].push_back(*it);
      }
      vector<Rect> rs2[4];
      FORIT(it, rect2) {
        rs2[it->dir].push_back(*it);
      }
      // cout << "test" << endl;
      // FORIT(it, rect1) {
      //   cout << *it << " " << it->dir << endl;
      // }
      // cout << "test" << endl;
      // FORIT(it, rect2) {
      //   cout << *it << " " << it->dir << endl;
      // }
      REP(dir, 4) {
        ans_dir = IntersectRect(rs1[dir], rs2[dir], false);
        if (ans_dir != -1) { break; }
      }
      REP(i, n) {
        ans_dirs[i] = ((ans_dir >> i) & 1) ? 1 : -1;
        // cout << (ans_dirs[i] == 1 ? "L" : "R");
      }
      // cout << endl;
    } else {
      // divide
      // cout << "Divide" << endl;
      ans_dir = Dfs(0, 0);
    }
    if (ans_dir == -1) {
      puts("-1");
      goto next;
    }

    // restore
    RestoreDistance();

    // print ans
    printf("%d\n", n);
    REP(i, n) {
      printf("%c %lld\n", ans_dirs[i] == 1 ? 'L' : 'R', ans_l[i]);
    }
    assert(Check());
next:;
  }
}

