#include <iostream>
using namespace std;

int minMoves(int H, int W, int K) {
    // Read the grid from standard input
    char grid[H][W];
    for (int i = 0; i < H; ++i) {
        for (int j = 0; j < W; ++j) {
            cin >> grid[i][j];
        }
    }

    // Initialize the distance matrix
    int dist[H][W];
    for (int i = 0; i < H; ++i) {
        for (int j = 0; j < W; ++j) {
            dist[i][j] = INT_MAX;
        }
    }

    // Distance matrix initialization
    for (int i = 0; i < H; ++i) {
        for (int j = 0; j < W; ++j) {
            if (grid[i][j] == 's') {
                dist[i][j] = 0;
            } else if (grid[i][j] == 'e') {
                dist[i][j] = INT_MAX;
            } else {
                dist[i][j] = INT_MAX;
            }
        }
    }

    // Directions for moving up, down, left, right
    int dx[] = {-1, 1, 0, 0};
    int dy[] = {0, 0, -1, 1};

    // Priority queue to store nodes to be visited
    priority_queue<pair<int, pair<int, int>>, vector<pair<int, pair<int, int>>>, greater<pair<int, pair<int, int>>>> pq;

    // Start from the square with the smallest distance
    pq.push({dist[0][0], {0, 0}});

    // Perform BFS
    while (!pq.empty()) {
        int d, x, y;
        tie(d, {x, y}) = pq.top();
        pq.pop();

        // If we have reached the goal, return the distance
        if (d == K) {
            return d;
        }

        // Explore all four possible directions
        for (int i = 0; i < 4; ++i) {
            int nx = x + dx[i];
            int ny = y + dy[i];

            // Check if the new position is within bounds and not a wall
            if (nx >= 0 && nx < H && ny >= 0 && ny < W && grid[nx][ny] != '#') {
                int newD = d + 1;
                int newX = nx;
                int newY = ny;

                // Update the distance if the new path is shorter
                if (newD < dist[newX][newY]) {
                    dist[newX][newY] = newD;
                    pq.push({newD, {newX, newY}});
                }
            }
        }
    }

    // If the goal cannot be achieved, return -1
    return -1;
}

int main() {
    int H, W, K;
    cin >> H >> W >> K;

    int result = minMoves(H, W, K);
    cout << result << endl;

    return 0;
}

