ll gcd(ll a, ll b, ll &x, ll &y)
{
	if (b == 0)
	{
		x = 1;
		y = 0;
		return a;
	}
	ll x1, y1;
	ll g = gcd(b, a%b, x1, y1);
	x = y1;
	y = x1 - (a / b) * y1;
	return g;
}

ll crt(ll a1, ll a2, ll n1, ll n2)
{
	ll x1, y1;
	ll d = gcd(n1, n2, x1, y1);
	if ((a1 - a2) % d != 0)
		return -1;

	ll k1 = (a2 - a1) / d * x1;
	ll t = a1 + n1 * (k1%n2);

	while (t < 0)
		t += n1 * n2 / d;

	if (t > (n1*n2) / d)
		t %= (n1*n2) / d;

	return t;
}

ll lccm;
vector<ll>pos1, pos2;
ll N = 0, n, m, k;

vector<ll>crts;

ll get(ll cnt)
{
	ll ans = cnt;
	for (int i = 0; i < N; i++)
	{
		if (pos1[i] == -1 || pos2[i] == -1)
			continue;
		else
		{
			ll fst = crts[i];
			if (fst != -1)
			{
				if (cnt - fst > 0)
				{
					ll t = cnt - fst;
					ans -= (t + lccm - 1) / lccm;
				}
			}
		}
	}
	return ans;
}

