	input(b);
	pos1.resize(N);
	pos2.resize(N);
	fill(all(pos1), -1);
	fill(all(pos2), -1);

	crts.resize(N);

	ll x, y;
	lccm = n * m / gcd(n, m, x, y);

	for (int i = 0; i < n; i++)
		pos1[a[i]] = i;
	for (int i = 0; i < m; i++)
		pos2[b[i]] = i;

	for (int i = 0; i < N; i++)
	{
		if (pos1[i] == -1 || pos2[i] == -1)
			continue;
		else
			crts[i] = crt(pos1[i], pos2[i], n, m);
	}

	ll l = 0, r = 1e18;
