int minMoney(int n) {
    std::vector<std::pair<int, int>> items(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> items[i].first >> items[i].second;
    }

    // Sort items by time in ascending order
    std::sort(items.begin(), items.end());

    int totalMoney = 0;
    int stolenItems = 0;

    // Iterate through sorted items
    for (const auto& item : items) {
        if (item.first == 0) {
            // Bob won't be able to steal anything
            continue;
        }
        // Calculate the time Bob spends stealing the item
        int timeToSteal = item.second - stolenItems;
        // Update total money
        totalMoney += timeToSteal * item.first;
        // Increment stolen items count
        stolenItems++;
    }

    return totalMoney;
}

