int minSecondsToChangeDoorPositions(int n, std::vector<std::pair<int, int>>& cupboardPositions) {
    // Sort the positions to ensure the left doors are always opened
    std::sort(cupboardPositions.begin(), cupboardPositions.end(), [](const auto& a, const auto& b) {
        return a.first < b.first;
    });

    int leftDoorCount = 0;
    int rightDoorCount = 0;

    // Count the number of left and right doors
    for (const auto& pos : cupboardPositions) {
        if (pos.first == 0) {
            ++leftDoorCount;
        } else {
            ++rightDoorCount;
        }
    }

    // Calculate the minimum number of seconds needed
    int seconds = (leftDoorCount + rightDoorCount - 1) / 2;

    return seconds;
}

