int maxArea(int n, int l, std::vector<int>& ai) {
    std::sort(ai.begin(), ai.end());
    int maxArea = 0;
    for (int i = 0; i < n; ++i) {
        int currentLength = ai[i];
        int previousLength = 0;
        for (int j = i + 1; j < n; ++j) {
            int nextLength = ai[j];
            if (currentLength > nextLength && currentLength - previousLength >= l) {
                maxArea = std::max(maxArea, (currentLength - previousLength) * l);
                break;
            }
            previousLength = currentLength;
        }
    }
    return maxArea;
}

