      for (int j = 0; j < n; j++)
        if (j != p) {
          if (is_on(ston[i], mon[p], mon[j])) adj[i][p].push_back(j);
          if (adj[i][p].size() >= k) break;
        }
    }
  }
  int res = 0;
  for (int i = 0; i < n; i++) {
    for (int j = 0; j < k; j++) id[j] = j;
    do {
      ++runs;
      used = 0;
      if (judge(i)) {
        res++;
        break;
      }
    } while (next_permutation(id, id + k));
  }
  printf("%d\n", res);
  return 0;
}

