}
void dfs(int x, int y, int ct) {
  if (tl) return;
  if ((x != 1 || y != 1) && ct == k) {
    tl = 1;
    for (int i = (1); i <= (n); i++)
      for (int j = (1); j <= (m); j++) as[i][j] = a[i][j];
