  t = 0;
  if (a[x - 1][y]) t += a[x][y + 1] + a[x - 1][y - 1] + a[x - 1][y + 1];
  if (a[x + 1][y]) t += a[x][y - 1] + a[x + 1][y - 1] + a[x + 1][y + 1];
  if (a[x][y - 1]) t += a[x - 1][y] + a[x - 1][y - 1] + a[x + 1][y - 1];
  if (a[x][y + 1]) t += a[x - 1][y + 1] + a[x + 1][y] + a[x + 1][y + 1];
  if (ct + t <= k && (x < 2 || y < 2 || a[x - 1][y] || a[x][y - 1])) {
    a[x][y] = 1;
    dfs(x, y + 1, ct + t);
    a[x][y] = 0;
  }
  dfs(x, y + 1, ct);
}
