    std::vector<std::string> likes(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> likes[i];
    }

    std::unordered_map<std::string, int> likesCount;
    for (const auto& like : likes) {
        likesCount[like]++;
    }

    int maxExperience = 0;
    int minExperience = std::numeric_limits<int>::max();
    int maxLiking = 0;
    int minLiking = std::numeric_limits<int>::min();

    for (const auto& like : likes) {
        int experience = likesCount[like];
        if (experience > maxExperience) {
            maxExperience = experience;
            maxLiking = 1;
        } else if (experience == maxExperience) {
            ++maxLiking;
        }

        if (experience < minExperience) {
            minExperience = experience;
            minLiking = 1;
        } else if (experience == minExperience) {
            ++minLiking;
        }
    }

    int difference = maxExperience - minExperience;
    int totalLiking = maxLiking + minLiking;

    std::cout << difference << " " << totalLiking << std::endl;

    return 0;
}

