        int id, p, q;
        std::cin >> id >> p >> q;
        sales.push_back({id, p, q});
    }

    int totalSales = 0;
    for (const auto& sale : sales) {
        totalSales += sale.second * sale.first;
    }

    std::vector<int> goodEmployees;
    for (const auto& sale : sales) {
