    if (goodEmployees.empty()) {
        std::cout << "NA" << std::endl;
    } else {
        std::cout << goodEmployees[0] << std::endl;
    }

    return 0;
}

#include <bits/stdc++.h>
using namespace std;
double mem[51][5001];
int x,y,z,v[100],used[51][5001];
struct po{int e,a;};
po E[101];

double dfs(int pos,int mo){
  if(pos==y) return mo;
  if(used[pos][mo]) return mem[pos][mo];
  used[pos][mo]=1;

  for(int i=0;i<x;i++) {
    int npos=min(y,pos+v[i]),nmo=mo;
    int e=E[npos].e, a=E[npos].a;
    if(e){
      if(e==1)npos=min(y,npos+a);
      if(e==2)nmo+=a;
      if(e==3)nmo=max(0,nmo-a);
    }
    mem[pos][mo] += dfs(npos,nmo)/x;
  }
  return mem[pos][mo];
}

