    std::cin >> X >> Y >> Z;

    int expected_value = 0;
    for (int i = 0; i < N; ++i) {
        int start = data[i][0];
        int goal = data[i][1];
        int event_square = data[i][2];
        int value = data[i][3];

        // Calculate the expected value of money at the goal
        int expected_value_at_goal = 0;
        for (int j = 0; j < Y; ++j) {
            int current_money = 0;
            for (int k = 0; k < X; ++k) {
                if (j == event_square) {
                    current_money += value;
                } else {
                    current_money += data[k][0];
                }
            }
            expected_value_at_goal += current_money;
        }

        // Update the expected value if the current goal is higher
        if (expected_value_at_goal > expected_value) {
            expected_value = expected_value_at_goal;
        }
    }

    std::cout << expected_value << std::endl;

    return 0;
}

