    for (int i = 0; i < W; ++i) {
        std::cin >> maze[i];
    }

    std::vector<std::vector<int>> scores(H, std::vector<int>(10, 0));

    // Read the collecting order scores
    for (int i = 0; i < H; ++i) {
        for (int j = 0; j < 10; ++j) {
            std::cin >> scores[i][j];
        }
    }

    int minMoves = 0;
    int maxScore = -1;

    // Try all possible paths to collect all items
    for (int i = 0; i < W; ++i) {
        for (int j = 0; j < 10; ++j) {
            if (scores[i][j] == 0) {
                int moves = 0;
                std::vector<int> path;
                path.push_back(i);
                path.push_back(j);

                // Explore all possible paths
                while (true) {
                    int nextX = path.back();
                    int nextY = path.back() + 1;
                    if (nextX >= 0 && nextX < W && nextY >= 0 && nextY < H) {
                        path.push_back(nextY);
                        moves++;
                        if (maze[nextX][nextY] == 9) {
                            break;
                        }
                    } else {
                        break;
                    }
                }

                // Update the minimum moves and maximum score
                if (moves < minMoves || (moves == minMoves && scores[i][j] > maxScore)) {
                    minMoves = moves;
                    maxScore = scores[i][j];
                }
            }
        }
    }

    std::cout << minMoves << " " << maxScore << std::endl;
    return 0;
}

