int main() {
    std::vector<int> inputs;
    int num;

    while (std::cin >> num) {
        inputs.push_back(num);
    }

    std::vector<std::pair<int, int>> results;

    for (int num : inputs) {
        int min_tetrahedral = 0;
        int min_odd_tetrahedral = 0;

        // Find the minimum number of tetrahedral numbers needed
        for (int i = 1; i <= num; ++i) {
            int tetrahedral_sum = i * (i + 1) / 2;
            if (tetrahedral_sum > num) {
                break;
            }
            min_tetrahedral += i;
        }

        // Find the minimum number of odd tetrahedral numbers needed
        for (int i = 1; i <= num; i += 2) {
            int odd_tetrahedral_sum = i * (i + 1) / 2;
            if (odd_tetrahedral_sum > num) {
                break;
            }
            min_odd_tetrahedral += i;
        }

        results.push_back({min_tetrahedral, min_odd_tetrahedral});
    }

    for (const auto& result : results) {
        std::cout << result.first << " " << result.second << std::endl;
    }

    return 0;
}

