#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<vector<int>> dist(n, vector<int>(n));

    // Read the distances from the input
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            cin >> dist[i][j];
        }
    }

    // Find the inverse of the distance matrix
    vector<vector<int>> invDist(n, vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            invDist[j][i] = dist[i][j];
        }
    }

    // Find the shortest path from each town to the next
    vector<int> shortestPath(n, INT_MAX);
    shortestPath[0] = 0;
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (invDist[i][j] != INT_MAX) {
                shortestPath[i] = min(shortestPath[i], shortestPath[j] + invDist[i][j]);
            }
        }
    }

    // Print the shortest paths
    for (int i = 0; i < n; ++i) {
        cout << shortestPath[i] << " ";
    }
    cout << endl;

    return 0;
}

