vector<int> solve(bitset<13>&used, vector<int>&nums) {
	if (used.count() == 13) {
		return vector<int>{-1};
	}
	else {
		for (int i = 0; i < 13; ++i) {
			if (!used[i]) {
				if (sum % (i + 1)==0) {
					sum+=(i+1)*nums[i];
					used[i] = true;
					auto v(solve(used, nums));
					if (!v.empty()) {
						if (v == vector<int>{-1}) {
							v.clear();
						}
						for (int j = 0; j < nums[i];++j) {

							v.push_back(i);
						}
						return v;
					}
					used[i]=false;
					sum-=(i+1)*nums[i];
				}
			}
		}
		return vector<int>();
	}

