int main() {
    int n;
    while (cin >> n) {
        if (n == 0) break;
        vector<int> seats(n);
        iota(seats.begin(), seats.end(), 1);

        // Sort the seats to handle rotations
        sort(seats.begin(), seats.end());

        int count = 0;
        for (int i = 0; i < n; ++i) {
            // Check if the current seat is the same as the next one
            if (seats[i] == seats[(i + 1) % n]) {
                continue;
            }

            // Check if the current seat is the same as the opposite one
            if (seats[i] == seats[(i - 1 + n) % n]) {
                continue;
            }

            // If none of the above conditions are met, it's a valid arrangement
            count++;
        }

        cout << count << endl;
    }

    return 0;
}

