vector<P> ConvexHull(vector<P> s){
  vector<P> g;
  int n = (int)s.size();

  if(n<3) return s;

  sort(s.begin(),s.end());

  for(int i=0;i<n;i++){
    for(int m = (int)g.size();m>=2 && ccw(g[m-2],g[m-1],s[i]); m--){
      g.pop_back();
    }
    g.push_back(s[i]);
  }

  int t = (int)g.size();

  for(int i=n-2;i>=0;i--){
    for(int m = (int)g.size();m>t && ccw(g[m-2],g[m-1],s[i]); m--){
      g.pop_back();
    }
    g.push_back(s[i]);
  }

  reverse(g.begin(),g.end());
  g.pop_back();

  return g;
}

