int pw(int n,int k){
  if(k<0)return pw(n,k+MOD-1);
  int res=1;
  while(k){
    if(k&1)res*=n;
    res%=MOD;
    n*=n;n%=MOD;
    k>>=1;
  }
  return res;
}
