#include <iostream>
#include <string>
#include <algorithm>

int minWeight(int n, int k, std::string s) {
    // Sort the stages alphabetically
    std::sort(s.begin(), s.end());

    // Initialize variables to track the current weight and the minimum weight found
    int currentWeight = 0;
    int minWeight = INT_MAX;

    // Iterate through each stage
    for (char stage : s) {
        // Calculate the weight of the current stage
        int weight = stage - 'a' + 1;

        // Update the current weight and the minimum weight if the current stage's weight is smaller
        currentWeight += weight;
        minWeight = std::min(minWeight, currentWeight);
    }

    // If the minimum weight is still INT_MAX, it means it's impossible to build the rocket
    return minWeight == INT_MAX ? -1 : minWeight;
}

