          dis[v] = dis[u] + w + h[u] - h[v];
          fnasiofnoas[v] = u;
          pree[v] = i;
          pq.push(node(v, dis[v]));
        }
      }
    }
    if (dis[t] == inf) break;
    for (int i = 0; i <= t; i++) h[i] += dis[i];
    int flow = inf;
    for (int i = t; i; i = fnasiofnoas[i])
      flow = min(flow, ed[fnasiofnoas[i]][pree[i]].c);
    tot -= flow;
    res += flow * h[t];
    for (int i = t; i; i = fnasiofnoas[i]) {
      edge &e = ed[fnasiofnoas[i]][pree[i]];
      e.c -= flow;
      ed[e.v][e.rev].c += flow;
    }
  }
  return res;
}
