using namespace std;
int arr[200005], tree[4 * 200005], lazy[4 * 200005];
struct info {
  int l, r, i;
};
vector<info> vec;
bool comp(info a, info b) {
  if (a.r != b.r) return a.r < b.r;
  return a.l < b.l;
}
void update(int node, int a, int b, int i, int j, int value) {
  if (lazy[node] != 0) {
    tree[node] += lazy[node];
    if (a != b) {
      lazy[node * 2] += lazy[node];
      lazy[node * 2 + 1] += lazy[node];
    }
    lazy[node] = 0;
  }
  if (a > b || a > j || b < i) return;
  if (a >= i && b <= j) {
    tree[node] += value;
    if (a != b) {
      lazy[node * 2] += value;
      lazy[node * 2 + 1] += value;
    }
    return;
  }
  int mid = (a + b) / 2;
  update(node * 2, a, mid, i, j, value);
  update(1 + node * 2, 1 + mid, b, i, j, value);
  tree[node] = max(tree[node * 2], tree[node * 2 + 1]);
}
int query(int node, int a, int b, int i, int j) {
  if (a > b || a > j || b < i) return 0;
  if (lazy[node] != 0) {
    tree[node] += lazy[node];
    if (a != b) {
      lazy[node * 2] += lazy[node];
      lazy[node * 2 + 1] += lazy[node];
    }
    lazy[node] = 0;
  }
  if (a >= i && b <= j) return tree[node];
  int mid = (a + b) / 2;
  int q1 = query(node * 2, a, mid, i, j);
  int q2 = query(1 + node * 2, 1 + mid, b, i, j);
  int res = max(q1, q2);
  return res;
}
