const long long INF = 2000000005;//00000;// autojs.org
const long long mod = 998244353;//1000000007;//
const int MAXN = 180;

struct vector {
	long long e[MAXN];
	vector() { memset(e, 0, sizeof(e)); }
	vector operator * (int a)
	{
		vector t = *this;
		for (int i = 0; i < MAXN; i++)
			t.e[i] = t.e[i] * a % mod;
		return t;
	}
	vector operator + (vector t)
	{
		for (int i = 0; i < MAXN; i++)
			t.e[i] = (t.e[i] + e[i]) % mod;
		return t;
	}
};
struct matrix {
	vector c[MAXN];

	vector operator * (vector &v)
	{
		vector t;
		for (int i = 0; i < MAXN; i++)
			t = t + c[i] * v.e[i];
		return t;
	}
	matrix operator * (matrix &m)
	{
		static matrix t;
	//	for (int i = 0; i < MAXN; i++)
	//		t.c[i] = (*this) * m.c[i];
		for (int i = 0; i < MAXN; i++)
			for (int j = 0; j < MAXN; j++)
			{
				t.c[j].e[i] = 0;
				for (int k = 0; k < MAXN; k++)
					t.c[j].e[i] += c[k].e[i] * m.c[j].e[k] % mod;
				t.c[j].e[i] %= mod;
			}
		return t;
	}
	long long &get(int i, int j) { return c[j].e[i]; }
	void print(int n)
	{
		for (int i = 0; i < n; i++)
			for (int j = 0; j < n; j++)
				printf("%lld%c", c[j].e[i], j == n - 1 ? '\n' : ' ');
	}
	static matrix ID()
	{
		static matrix I;
		for (int i = 0; i < MAXN; i++)
			I.get(i, i) = 1;
		return I;
	}
};
void qpow(matrix &A, int x)
{
	if (!x)
	{
		A = matrix::ID();
		return;
	}
	if (x & 1)
	{
		matrix t = A;
		qpow(A, x / 2);
		A = A * A * t;
	}
	else
	{
		qpow(A, x / 2);
		A = A * A;
	}
}

