						for (int t = 0; t < N; t++)
							if (len[t] <= len[s] && streql(str[s], str[t], len[t]))
								A.get(id(s, len[s] - 1, len[t] - 1), id(i, j, k))
								+= 1ll + (len[t] != len[s]);
