						if (len[s] <= j && streql(str[i] + len[i] - j, str[s], len[s]))
							A.get(id(i, j - 1, len[s] - 1), id(i, j, k))++;
						else if (len[s] > j && streql(str[i] + len[i] - j, str[s], j))
							A.get(id(s, len[s] - 1, j - 1), id(i, j, k))++;
