			int two = (pre[n - 1] - key);

			for (int i = 0; i < n; i++) {

				if (a[i].second > two) return false;
				two += a[i].first;

				if (pre[i] >= key) break;

			}

			return true;

		};
		while (r >= l) {
			int mid = (l + r) / 2;
			if (check(mid)) ans = mid, l = mid + 1;
			else r = mid - 1;
		}

		cout << (ans + (pre[n - 1] - ans) * 2) << endl;

	}
	return 0;
}

int power(int a, int b)
{
	int res = 1;
	while (b)
	{
		if (b % 2) b-- , res = res * a;
		else b = b / 2 , a *= a;
	}
	return res;
}

