struct uzi {
  long long A[44][44];
  uzi() { memset(A, 0x3f3f3f, sizeof A); };
} G;
uzi operator*(const uzi& a, const uzi& b) {
  uzi c;
  for (int i = 0; i <= 40; i++) {
    for (int j = 0; j <= 40; j++) {
      for (int k = 0; k <= 40; k++) {
        c.A[i][j] = min(a.A[i][k] + b.A[k][j], c.A[i][j]);
      }
    }
  }
  return c;
}
uzi pm() {
  uzi c;
  for (int i = 0; i <= 40; i++) c.A[i][i] = 0;
  while (m) {
    if (m & 1) c = c * G;
    G = G * G;
    m >>= 1;
  }
  return c;
}
