int mv[4][2] = {{0, -1}, {0, 1}, {1, 0}, {-1, 0}};
void bfs(int x, int y) {
  queue<Node> q;
  int xt, yt;
  Node tmp, next;
  tmp.x = x;
  tmp.y = y;
  book[x][y] = true;
  cnt = 1;
  q.push(tmp);
  while (!q.empty()) {
    tmp = q.front();
    q.pop();
    for (int i = 0; i < 4; i++) {
      xt = tmp.x + mv[i][0];
      yt = tmp.y + mv[i][1];
      if (xt < 1 || xt > n || yt < 1 || yt > m) continue;
      if (!book[xt][yt] && mapp[xt][yt] == '.') {
        if (cnt == sum - k) return;
        book[xt][yt] = true;
        cnt++;
        next.x = xt;
        next.y = yt;
        q.push(next);
      }
    }
  }
}
