// Function to check if two strings can be transformed into each other using suffix automaton
bool canTransformWithSuffixAutomaton(const std::string& s, const std::string& t) {
    // Check if the lengths of the strings are different
    if (s.length() != t.length()) {
        return false;
    }

    // Create suffix arrays for both strings
    std::vector<int> sa(s.size());
    std::vector<int> saT(t.size());

    // Compute suffix arrays
    for (int i = 0; i < s.size(); ++i) {
        sa[i] = s.size() - 1 - std::string::find(s.rbegin() + i, s.rend(), s[i]);
    }
    for (int i = 0; i < t.size(); ++i) {
        saT[i] = t.size() - 1 - std::string::find(t.rbegin() + i, t.rend(), t[i]);
    }

    // Check if the suffix arrays match
    for (int i = 0; i < s.size(); ++i) {
        if (sa[i] != saT[i]) {
            return false;
        }
    }

    return true;
}

int main() {
    // Read input strings
    std::string s, t;
    std::cin >> s >> t;

    // Check if the strings can be transformed using suffix automaton
    if (canTransformWithSuffixAutomaton(s, t)) {
        std::cout << "automaton" << std::endl;
    } else {
        std::cout << "need tree" << std::endl;
    }

    return 0;
}

