double areaOfSnowblower(int n, vector<vector<int>>& v) {
    double area = 0;
    for (int i = 0; i < n; ++i) {
        int x1 = v[i][0], y1 = v[i][1];
        int x2 = v[(i + 1) % n][0], y2 = v[(i + 1) % n][1];
        double dx = x2 - x1;
        double dy = y2 - y1;
        area += abs(dx * dy) / 2.0;
    }
    return area;
}

