int n;
const int N = 420000 * 2;
struct Edge {
  int u, v, nxt;
} e[N];
int head[N], en;
void addl(int x, int y) {
  e[++en].u = x, e[en].v = y, e[en].nxt = head[x], head[x] = en;
}
bool ans[N];
int siz[N], rt, res = 1e9;
void dfs(int x, int F) {
  siz[x] = 1;
  int mx = 0;
  for (int i = head[x]; i; i = e[i].nxt) {
    int y = e[i].v;
    if (y == F) continue;
    dfs(y, x);
    siz[x] += siz[y];
    mx = max(mx, siz[y]);
  }
  mx = max(mx, n - siz[x]);
  if (mx < res) {
    res = mx;
    rt = x;
  }
}
vector<pair<int, int> > sub;
void solve(int x, int F, int sum, int pre) {
  if (sum <= n / 2) ans[x] = 1;
  for (int i = 0; i < 2 && i < sub.size(); ++i) {
    if (sub[i].second == pre) continue;
    if (n - siz[x] - sub[i].first <= n / 2) ans[x] = 1;
  }
  for (int i = head[x]; i; i = e[i].nxt) {
    int y = e[i].v;
    if (y == F) continue;
    solve(y, x, sum, pre);
  }
}
