  n = read();
  for (int i = 1; i < n; ++i) {
    int x = read(), y = read();
    addl(x, y);
    addl(y, x);
  }
  dfs(1, 0);
  dfs(rt, 0);
  ans[rt] = 1;
  for (int i = head[rt]; i; i = e[i].nxt)
    sub.push_back(make_pair(siz[e[i].v], e[i].v));
  sort(sub.begin(), sub.end(), greater<pair<int, int> >());
  for (int i = head[rt]; i; i = e[i].nxt) {
    int to = e[i].v;
    solve(to, rt, n - siz[to], to);
  }
