int check(map<int, int>& height, int k) {
  for (auto& [v, h] : height) {
    if (h == k) {
      return v;
    } else if (h + 1 == k) {
      auto edges = ask(v);
      for (auto u : edges) {
        auto edges_u = ask(u);
        if (edges_u.size() == 2u) {
          return u;
        }
      }
    } else if (h + 2 == k) {
      auto edges_v = ask(v);
      set<int> cands;
      for (auto u : edges_v) {
        auto edges_u = ask(u);
        for (auto w : edges_u) {
          if (memo.count(w)) {
            if (memo[w].size() == 2) {
              return w;
            }
          } else if (w != v) {
            cands.insert(w);
          }
        }
      }
      assert(cands.size() > 0);
      while (cands.size() > 1) {
        auto cand = *cands.begin();
        cands.erase(cands.begin());
        auto resp = ask(cand);
        if (resp.size() == 2) {
          return cand;
        }
      }
      return *cands.begin();
    }
  }
  return 0;
}
void solve() {
