  set<int> used;
  used.insert(first);
  while (true) {
    int v = -1;
    for (auto u : resp) {
      if (!used.count(u)) {
        v = u;
        used.insert(v);
        break;
      }
    }
    chain.push_back(v);
    resp = ask(v);
    if (resp.size() == 2u) {
      cout << "! " << v << endl;
      return;
    }
    if (resp.size() == 1) {
      break;
    }
  }
  if (memo[first].size() > 1) {
    reverse(chain.begin(), chain.end());
    resp = memo[first];
    while (true) {
      int v = -1;
      for (auto u : resp) {
        if (!used.count(u)) {
          v = u;
          used.insert(v);
          break;
        }
      }
      chain.push_back(v);
      resp = ask(v);
      if (resp.size() == 2u) {
        cout << "! " << v << endl;
        return;
      }
      if (resp.size() == 1) {
        break;
      }
    }
  }
  map<int, int> height;
  for (size_t i = 0; i < chain.size(); ++i) {
    int cur_h = (int)i + 1;
    if (i > chain.size() / 2) {
      cur_h = (int)(chain.size() - i);
    }
    height[chain[i]] = cur_h;
  }
  assert(chain.size() % 2);
  for (auto u : memo[chain[chain.size() / 2]]) {
    if (!height.count(u)) {
      height[u] = height[chain[chain.size() / 2]] + 1;
    }
  }
  while (true) {
    int answer = check(height, k);
    if (answer) {
      cout << "! " << answer << endl;
      return;
    }
    int max_h = -1;
    int v = -1;
    for (auto& [u, h] : height) {
      if (h > max_h) {
        max_h = h;
        v = u;
      }
    }
    int cur_v = v;
    vector<int> path = {cur_v};
    for (int i = 0; i < max_h - 1; ++i) {
      auto resp = ask(cur_v);
      if (resp.size() == 2) {
        cout << "! " << cur_v << endl;
        return;
      }
      for (auto u : resp) {
        if (!height.count(u) &&
            (path.size() < 2 || u != path[(int)path.size() - 2])) {
          cur_v = u;
          path.push_back(cur_v);
          break;
        }
      }
    }
    auto resp = ask(cur_v);
    if (resp.size() == 2) {
      cout << "! " << cur_v << endl;
      return;
    } else if (resp.size() == 1u) {
      reverse(path.begin(), path.end());
      for (size_t i = 0; i < path.size(); ++i) {
        height[path[i]] = i + 1;
      }
      reverse(path.begin(), path.end());
      for (auto u : ask(v)) {
        if (!height.count(u) && u != path[1]) {
          height[u] = height[v] + 1;
          break;
        }
      }
    } else {
      height[path[1]] = height[v] + 1;
    }
  }
}
