inline long long ps(long long x, long long y, long long P) {
  long long z = 0;
  while (y) {
    if (y & 1) z = z + x;
    x <<= 1, y >>= 1;
    if (x >= P) x -= P;
    if (z >= P) z -= P;
  }
  return z;
}
inline long long pm(long long x, long long y, long long P) {
  long long z = 1;
  x %= P;
  while (y) {
    if (y & 1) z = ps(z, x, P);
    x = ps(x, x, P), y >>= 1;
  }
  return z;
}
