bool Calc(int n,string s){
	//int n=read();
	//string s=string("1")+readString()+string("1");
	s=string("1")+s+string("1");
	REP(i,n*2)match[i]=-1;
	vi pos00,pos01,pos10,pos11;
	REP(i,n*2){
		if(s[i]=='0'){
			if(s[i+1]=='0'){
				pos00.PB(i);
			}else{
				pos01.PB(i);
			}
		}else if(s[i]=='1'){
			if(s[i+1]=='0'){
				pos10.PB(i);
			}else{
				pos11.PB(i);
			}
		}
	}
	if(int(pos00.size())%2==1){
		//Muri();
		return false;
	}
	for(int i=0;i<int(pos00.size());i+=2)
		Match(pos00[i],pos00[i+1]);
	if(int(pos11.size())%4==0){
		// do nothing
	}else{
		vi ss;
		int cur=0;
		REP(i,n*2+1)
			if(s[i]=='1'){
				cur++;
				if(i==n*2||s[i+1]=='0')
					ss.PB(cur);
			}else
				cur=0;
		if(int(ss.size())==1)
			return false;
		int cnt1=0,cnt2=0;
		FOR(i,1,int(ss.size())-1)
			if(ss[i]>1)cnt1++;
		if(ss[0]>1)cnt2++;
		if(ss.back()>1)cnt2++;
		if(cnt1==0||cnt1+cnt2<=1)
			return false;

		vector<vi> z;
		{
			vi w;
			int last=pos11.front()-1;
			for(auto p:pos11){
				if(last+1<p){
					z.PB(w);
					w.clear();
				}
				last=p;
				w.PB(p);
			}
			z.PB(w);
