			pos11.clear();
			for(auto zz:z)for(auto zzz:zz)
				pos11.PB(zzz);
		}
	}
	REP(i,pos01.size())
		Match(pos01[i],pos10[i]);
	assert(int(pos11.size())%4==0);
	for(int i=0;i<int(pos11.size());i+=4){
		Match(pos11[i],pos11[i+2]);
		Match(pos11[i+1],pos11[i+3]);
	}
	//REACH;
	//ShowMatch(n);
	return true;
}

