		ZERO(vis);
		int pos=0;
		while(pos<n*2){
			pos=match[pos];
			vis[pos]=true;
			pos++;
		}
		REP(i,n*2-1)
			if((s[i]=='1')^vis[i])
				return false;
		return true;
	}
	bool rec(int n,string s){
		int a=find(match,match+n*2,-1)-match;
		if(a==n*2)
			return Go(n,s);
		FOR(b,a+1,n*2)if(match[b]==-1){
			match[a]=b;
			match[b]=a;
			if(rec(n,s))return true;
			match[a]=-1;
			match[b]=-1;
		}
		return false;
	}
	bool Calc(int n,string s){
		REP(i,n*2)match[i]=-1;
		return rec(n,s);
	}
}

