			speP x = q.top(); q.pop();
			int v = x.second;
			if (x.first > d[v])continue;
			int len = G[v].size();
			rep(j, len) {
				int nex = G[v][j].to;
				ld c = G[v][j].cost;
				if (d[nex] > d[v] + c) {
					d[nex] = d[v] + c;
					q.push({ d[nex],nex });
