const int maxn = 150001;
struct BIT {
  int bit[maxn];
  BIT() { memset(bit, 0, sizeof(bit)); }
  void add(int x, int v) {
    for (x++; x < maxn; x += x & -x) bit[x] += v;
  }
  void add(int a, int b, int v) { add(a, 1), add(b + 1, -1); }
  int qry(int x) {
    int ret = 0;
    for (x++; x; x -= x & -x) ret += bit[x];
    return ret;
  }
};
struct segTree {
  int l, r;
  segTree *left = 0, *right = 0;
  int val = 0;
  segTree(int a, int b) : l(a), r(b){};
  void add(int x, int v) {
    if (l == r) {
      val += v;
      return;
    }
    int mid = (l + r) / 2;
    if (x <= mid) {
      if (!left) left = new segTree(l, mid);
      left->add(x, v);
    } else {
      if (!right) right = new segTree(mid + 1, r);
      right->add(x, v);
    }
    val = (left ? left->val : 0) + (right ? right->val : 0);
  }
  void mrg(segTree *tre) {
    if (!tre) return;
    if (!left)
      left = tre->left;
    else if (tre->left)
      left->mrg(tre->left);
    if (!right)
      right = tre->right;
    else if (tre->right)
      right->mrg(tre->right);
    val += tre->val;
    delete tre;
  }
  int qry(int a, int b) {
    if (a <= l && r <= b) return val;
    int ret = 0, mid = (l + r) / 2;
    if (a <= mid && b >= l && left) ret += left->qry(a, b);
    if (b > mid && a <= r && right) ret += right->qry(a, b);
    return ret;
  }
  void clear() {
    if (left) left->clear();
    if (right) right->clear();
    delete this;
  }
};
