int dfsh(int c) {
  sz[c] = 1, h[c] = -1;
  for (int i = 1; i < w; i++) {
    p[i][c] = ~p[i - 1][c] ? p[i - 1][p[i - 1][c]] : -1;
  }
  for (int i : graph[c]) {
    if (i == p[0][c]) continue;
    p[0][i] = c;
    d[i] = d[c] + 1;
    sz[c] += dfsh(i);
    if (!~h[c] || sz[i] > sz[h[c]]) h[c] = i;
  }
  return sz[c];
}
int dfsh2(int c) {
  r[c] = l[c];
  for (int i : graph[c]) {
    if (i == p[0][c] || i == h[c]) continue;
    l[i] = r[c] + 1;
    r[c] = dfsh2(i);
  }
  if (~h[c]) {
    l[h[c]] = r[c] + 1;
    r[c] = dfsh2(h[c]);
  }
  return r[c];
}
int lft(int c, int x) {
  for (int i = 0; i < w; i++) {
    if (((x >> i) & 1) && ~c) c = p[i][c];
  }
  return c;
}
int lca(int x, int y) {
  if (d[x] < d[y]) swap(x, y);
  x = lft(x, d[x] - d[y]);
  for (int i = w - 1; ~i; i--) {
    if (p[i][x] != p[i][y]) x = p[i][x], y = p[i][y];
  }
  return x == y ? x : p[0][x];
}
long long dfs2(int c, int rt) {
  long long ret = 0;
  tre[c] = new segTree(0, n - 1);
  for (int i : v2[c]) {
    int dd = max(0, k + d[rt] - d[q[i][0]]);
    int j = q[i][1];
    if (d[j] - d[rt] >= dd) {
      j = lft(j, d[j] - d[rt] - dd);
      ret += tre[c]->qry(l[j], r[j]);
    }
    tre[c]->add(l[q[i][1]], 1);
  }
  for (int i : graph[c]) {
    if (i == p[0][c] || (c == rt && i == h[c])) continue;
    ret += dfs2(i, rt);
    if (v2[c].size() < v2[i].size()) {
      swap(v2[c], v2[i]);
      swap(tre[c], tre[i]);
    }
    for (int it : v2[i]) {
      int dd = max(0, k + d[rt] - d[c]);
      int j = q[it][1];
      if (d[j] - d[rt] >= dd) {
        j = lft(j, d[j] - d[rt] - dd);
        ret += tre[c]->qry(l[j], r[j]);
      }
      v2[c].push_back(it);
    }
    v2[i].clear();
    tre[c]->mrg(tre[i]);
  }
  return ret;
}
long long dfs(int c) {
  long long ret = 0;
  for (int i : graph[c])
    if (i != p[0][c]) ret += dfs(i);
  for (int t = 0; t < 2; t++) {
    for (int i : v[c]) ret += bit.qry(l[q[i][t]]);
    for (int i : v[c]) {
      int j = q[i][t];
      if (d[j] - d[c] >= k) {
        j = lft(j, d[j] - d[c] - k);
        bit.add(l[j], r[j], 1);
      }
      if (!t) v2[q[i][t]].push_back(i);
    }
  }
  ret += dfs2(c, c);
  v2[c].clear();
  tre[c]->clear();
  return ret;
}
