int gao(int l, int r) {
  int &res = dp[l][r];
  if (~res) return res;
  if (l == r) return dpc[l][r] = 3, res = 1;
  if (l > r) return dpc[l][r] = 4, res = 0;
  res = 0;
  int t;
  if (s[l] == s[r]) {
    t = gao(l + 1, r - 1) + 2;
    if (t > res) res = t, dpc[l][r] = 3;
  }
  t = gao(l + 1, r);
  if (t > res) res = t, dpc[l][r] = 1;
  t = gao(l, r - 1);
  if (t > res) res = t, dpc[l][r] = 2;
  return res;
}
