  long long lo = l, hi = r;
  long long mmin = min(m, r);
  for (long long w = 1; w <= mmin; ++w) {
    while (lo > 1 && l * l - w * w <= (lo - 1) * (lo - 1)) --lo;
    while (r * r - w * w < hi * hi) --hi;
