int pow(int a, int b) {
  long long res = 1, tmp = a;
  while (b) {
    if (b & 1) res = res * tmp % mod;
    tmp = tmp * tmp % mod;
    b >>= 1;
  }
  return res;
}
void solve() {
  long long sum = 0;
  long long ans = 0;
  long long ten = 1;
  long long c = 1;
