    printf("%I64d\n", ans);
    return;
  }
  for (int i = (n - k); i <= (n - 2); ++i) c = c * i % mod;
  for (int i = (1); i <= (k - 1); ++i) c = c * inv[i] % mod;
  for (int i = (0); i < (n - k); ++i) {
    sum = ((sum - a[n - i]) % mod + mod) % mod;
    long long tmpc = c * inv[k] % mod * (n - i - 1) % mod;
    ans = (ans + ten * sum % mod * c) % mod;
    ans = (ans + ten * a[n - i] % mod * tmpc) % mod;
    ten = ten * 10 % mod;
    c = c * (n - k - i - 1) % mod;
    c = c * inv[n - i - 2] % mod;
  }
  printf("%I64d\n", ans);
}
