bool check_path(int &i, int &j, int &e, int &fi, int &fj, int &fe) {
  if (!check(i, j, e) || !check(fi, fj, fe)) return false;
  if (i > fi || j > fj || e > fe) return false;
  if (state[i][j][e] == 0) return false;
  if (i == fi && j == fj && e == fe) return true;
  for (int t = 0; (t) < 3; ++(t)) {
