long long solve(int mask, int i) {
  if (i == n) {
    for (int j = 0; j < 30; j++) {
      if (mask == b[j]) {
        return 1;
      }
    }
    return 0;
  }
  int &ret = memo[mask][i];
  if (ret != -1) return ret;
  int sum = 0;
  for (int j = 0; j < 75; j++) {
    if (i + j <= n) {
      int num = 0;
      for (int k = 0; k < j; k++) {
