#include <iostream>
#include <vector>
#include <algorithm>

int minExchanges(int n, std::vector<int>& a, std::vector<int>& b) {
    // Sort the arrays to facilitate finding the minimum number of exchanges
    std::sort(a.begin(), a.end());
    std::sort(b.begin(), b.end());

    int exchanges = 0;
    int i = 0, j = 0;

    while (i < n && j < n) {
        // If the current students have the same performance, increment the exchange count
        if (a[i] == b[j]) {
            ++exchanges;
            ++i;
            ++j;
        } else {
            // If the current students have different performances, find the closest pair
            int closestPair = std::min(a[i], b[j]);
            int index = std::lower_bound(a.begin(), a.end(), closestPair) - a.begin();
            int nextIndex = std::upper_bound(b.begin(), b.end(), closestPair) - b.begin();

            // If the next index is within the bounds of the array, increment the exchange count
            if (nextIndex < n) {
                ++exchanges;
                ++i;
                ++j;
            } else {
                // If the next index is out of bounds, break the loop
                break;
            }
        }
    }

    return exchanges;
}

int main() {
    int n;
    std::cin >> n;

    std::vector<int> a(n);
    std::vector<int> b(n);

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        std::cin >> b[i];
    }

    int result = minExchanges(n, a, b);

    if (result == -1) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result << std::endl;
    }

    return 0;
}

#include <bits/stdc++.h>
using namespace std;
const int N = 200500;
struct state {
  int len, link;
  map<char, int> next;
};
state st[N];
int sz, last;
void sa_init() {
  last = st[0].len = 0;
  sz = 1;
  st[0].link = -1;
}
void sa_extend(char c) {
  int k = sz++, p;
  st[k].len = st[last].len + 1;
  for (p = last; p != -1 && !st[p].next.count(c); p = st[p].link)
    st[p].next[c] = k;
  if (p == -1)
    st[k].link = 0;
  else {
    int q = st[p].next[c];
    if (st[p].len + 1 == st[q].len)
      st[k].link = q;
    else {
      int w = sz++;
      st[w].len = st[p].len + 1;
      st[w].next = st[q].next;
      st[w].link = st[q].link;
      for (; p != -1 && st[p].next[c] == q; p = st[p].link) st[p].next[c] = w;
      st[q].link = st[k].link = w;
    }
  }
  last = k;
}
string s;
long long dp[N];
bool t[N];
long long f(int i) {
  if (dp[i] != -1) return dp[i];
  long long &r = dp[i] = t[i];
  for (auto p : st[i].next) r += f(p.second);
  return r;
}
void solve() {
  sa_init();
  memset(dp, -1, sizeof dp);
  for (int i = 0, qwerty = ((int)(s).size()); i < qwerty; i++) sa_extend(s[i]);
  int x = last;
  while (x) {
    t[x] = 1;
    x = st[x].link;
  }
  f(0);
  long long r = 0;
  for (int i = 1, qwerty = sz; i < qwerty; i++)
    r += f(i) * f(i) * (st[i].len - st[st[i].link].len);
  while (last) {
    t[last] = 0;
    last = st[last].link;
  }
  for (int i = 0, qwerty = sz; i < qwerty; i++) st[i].next.clear();
  cout << r << "\n";
}
int main() {
  ios_base::sync_with_stdio(0);
  cin.tie(0);
  cout.tie(0);
  int tn;
  cin >> tn;
  for (int i = 0, qwerty = tn; i < qwerty; i++) {
    cin >> s;
    solve();
  }
}

