#include <algorithm>

int minPointsToRemove(int n, int d, std::vector<int>& points) {
    // Sort the points by their x-coordinates
    std::sort(points.begin(), points.end());

    // Initialize the diameter to the maximum possible value
    int diameter = INT_MAX;

    // Iterate through the sorted points to find the minimum diameter
    for (size_t i = 0; i < n - 1; ++i) {
        int currentDiameter = points[i + 1] - points[i];
        if (currentDiameter > diameter) {
            diameter = currentDiameter;
        }
    }

    // If the diameter is still greater than d, return 0
    if (diameter > d) {
        return 0;
    }

    // Otherwise, return the minimum number of points to remove
    return n - diameter;
}

int main() {
