const int N = 5005, P = 1000000007;

int n, type, D;
std::vector<int> E[N];
int fa[N];

std::pair<int, int> dfs(int u, int fa = 0) {
	std::pair<int, int> res(0, u);
	for (int v : E[u]) {
		if (v != fa) {
			std::pair<int, int> tmp = dfs(v, u);
			++tmp.first;
			res = std::max(res, tmp);
		}
	}
	return res;
}

void getfa(int u) {
	for (int v : E[u]) {
		if (v != fa[u]) {
			fa[v] = u, getfa(v);
		}
	}
}

int f[N][N << 1];

void DP(int u, int fa, int d) {
	for (int i = -D; i <= D; ++i) {
		f[u][i + D] = -d <= i && i <= d;
	}
	for (int v : E[u]) {
		if (v != fa) {
			DP(v, u, d - 1);
			for (int i = 0; i <= 2 * D; ++i) {
				f[u][i] = 1ll * f[u][i] * ((i == 0 ? 0 : f[v][i - 1]) + (i == 2 * D ? 0 : f[v][i + 1])) % P;
			}
		}
	}
}

int main() {
	read(n);
	for (int i = 1; i < n; ++i) {
		int u, v;
		read(u), read(v);
		E[u].push_back(v), E[v].push_back(u);
	}
	int S = dfs(1).second, T;
	std::pair<int, int> tmp = dfs(S);
	T = tmp.second;
	D = tmp.first;
	getfa(S);
	if (D & 1) {
		D = (D + 1) >> 1;
		int s, t = T, ans = 0;
		for (int i = 1; i < D; ++i) {
			t = fa[t];
		}
		s = fa[t];
		DP(s, t, D), DP(t, s, D - 1);
		for (int i = 0; i <= 2 * D; ++i) {
			ans = (ans + 1ll * f[s][i] * f[t][i + 1]) % P;
			ans = (ans + 1ll * f[t][i] * f[s][i + 1]) % P;
		}
		DP(s, t, D - 1), DP(t, s, D);
		for (int i = 0; i <= 2 * D; ++i) {
			ans = (ans + 1ll * f[s][i] * f[t][i + 1]) % P;
			ans = (ans + 1ll * f[t][i] * f[s][i + 1]) % P;
		}
		DP(s, t, D - 1), DP(t, s, D - 1);
		for (int i = 0; i <= 2 * D; ++i) {
			ans = (ans - 2ll * f[s][i] * f[t][i]) % P;
			ans = (ans - 1ll * f[s][i] * f[t][i + 2]) % P;
			ans = (ans - 1ll * f[t][i] * f[s][i + 2]) % P;
		}
		print((ans + P) % P);
	} else {
		D >>= 1;
		int r = T, ans = 0;
		for (int i = 1; i <= D; ++i) {
			r = fa[r];
		}
		DP(r, 0, D);
		for (int i = 0; i <= 2 * D; ++i) {
			ans = (ans + f[r][i]) % P;
		}
		print(ans);
	}
}

