        int max_mining = 0;
        for (int j = 0; j < N; ++j) {
            for (int k = 0; k < N; ++k) {
                if (reserve[j][k] == 1) {
                    int left = std::max(0, j - 1);
                    int right = std::min(N - 1, j + 1);
                    int up = std::max(0, k - 1);
                    int down = std::min(N - 1, k + 1);

                    int current_mining = reserve[left][up] + reserve[right][down] + reserve[left][down] + reserve[right][up];

                    max_mining = std::max(max_mining, current_mining);
                }
            }
        }

        std::cout << "Case " << i << ": " << max_mining << std::endl;
    }

    return 0;
