int next(int bit){
  int ret = bit;
  for(int i=0;i<7;++i){
	int tmp = 0;
	for(int j=0;j<7;++j){
	  tmp |= ((bit>>crd[i][j]) & 1) << j;
	  ret = (ret & ~(1<<i)) | (filt[tmp] << i);
	}
  }

  return ret;
}

