    for (int i = 0; i < H; ++i) {
        for (int j = 0; j < W; ++j) {
            cin >> damage[i][j];
        }
    }

    // Initialize variables to track the position of the typhoon
    int x = 0, y = 0;
    int t = 0;

    // Iterate through all possible positions of the typhoon
    while (true) {
        // Check if the typhoon has hit the sky
        if (damage[x][y] == 3) {
            break;
        }

        // Calculate the new position of the typhoon
        int nx = x + damage[x][y];
        int ny = y + damage[x][y];

        // Check if the typhoon has moved to an extratropical cyclone
        if (nx >= 0 && nx < H && ny >= 0 && ny < W && damage[nx][ny] == 0) {
            t++;
            x = nx;
            y = ny;
        } else {
            break;
        }
    }

    // Output the final position of the typhoon
    cout << x << " " << y << " " << t << endl;

    return 0;
}

