int minCostToSort(std::vector<int>& w) {
    int n = w.size();
    std::vector<int> sortedW(w);
    std::sort(sortedW.begin(), sortedW.end());

    int cost = 0;
    for (int i = 0; i < n; ++i) {
        cost += sortedW[i] - w[i];
    }

    return cost;
}

