#include <iostream>
#include <vector>
#include <algorithm>

int minComplexity(int n, std::vector<int>& p) {
    // Sort the array to make it easier to find adjacent pairs
    std::sort(p.begin(), p.end());

    int complexity = 0;
    for (size_t i = 0; i < n - 1; ++i) {
        // Check if the current pair has different parity
        if ((p[i] % 2 != p[i + 1] % 2)) {
            complexity++;
        }
    }

    return complexity;
}

int main() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    int result = minComplexity(n, p);
    std::cout << result << std::endl;

    return 0;
}

