std::string nextPalindrome(const std::string& s) {
    int n = s.size();
    for (int i = n - 2; i >= 0; --i) {
        if (s[i] < s[i + 1]) {
            // Find the longest suffix starting from i that is less than the current character
            int j = i + 1;
            while (j < n && s[j] <= s[i]) ++j;
            // Swap the characters at i and j
            std::swap(s[i], s[j]);
            // Reverse the suffix starting from i+1
            std::reverse(s.begin() + i + 1, s.end());
            return s;
        }
    }
    return "NO";
}

