int maxPairs(int n, std::vector<int>& a, int m, std::vector<int>& b) {
    // Sort the arrays to make it easier to find the maximum difference
    std::sort(a.begin(), a.end());
    std::sort(b.begin(), b.end());

    int count = 0;
    int i = 0, j = 0;

    // Iterate through both arrays
    while (i < n && j < m) {
        // If the current pair's difference is at most 1, increment the count
        if (std::abs(a[i] - b[j]) <= 1) {
            count++;
            i++;
            j++;
        } else {
            // If the current pair's difference is more than 1, move to the next pair
            if (a[i] > b[j]) {
                j++;
            } else {
                i++;
            }
        }
    }

    return count;
}

