    int64_t res = 0;
    for (int i = int(0); i < int(m); ++i) {
      ;
      res = (res + a[t + 2 * i] * c(i, m - 1 - i)) % mod;
    };
    return res;
  }
  void solve() {
    f[0] = 1;
    for (int i = int(0); i < int(n); ++i) {
      f[i + 1] = f[i] * (i + 1) % mod;
    }
    for (int i = int(0); i < int(n + 1); ++i) {
      rf[i] = pw(f[i], mod - 2);
    }
