    ans.push_back(make_pair(by_idx[bucket], w));
    filled[bucket] = false;
    filled.back() = true;
    wanted.erase(find((wanted).begin(), (wanted).end(), bucket));
    ws_to[w] = ws_to[by_idx[bucket]];
  }
  queue<int> wfa, wfb;
  for (int u : wanted) {
    if (u < numf)
      wfa.push(u);
    else
      wfb.push(u);
  }
  while (wfa.size() && wfb.size()) {
    int a;
    if (bucket < numf) {
      a = wfb.front();
      wfb.pop();
    } else {
      a = wfa.front();
      wfa.pop();
    }
    ans.push_back(make_pair(by_idx[a], by_idx[bucket]));
    filled[bucket] = true;
    filled[a] = false;
    bucket = a;
  }
  queue<int> free_a;
  queue<int> free_b;
  for (int i = 0; i < ((int)(numf)); ++i)
    if (!filled[i]) free_a.push(i);
  for (int i = (int)(numf); i < ((int)(n)); ++i)
    if (!filled[i]) free_b.push(i);
  while (wfa.size()) {
    int a = wfa.front();
    wfa.pop();
    int b = free_b.front();
    free_b.pop();
    ans.push_back(make_pair(by_idx[a], by_idx[b]));
    filled[a] = false;
    filled[b] = true;
  }
  while (wfb.size()) {
    int a = wfb.front();
    wfb.pop();
    int b = free_a.front();
    free_a.pop();
    ans.push_back(make_pair(by_idx[a], by_idx[b]));
    filled[a] = false;
    filled[b] = true;
  }
  free_a = queue<int>();
  free_b = queue<int>();
  for (int i = 0; i < ((int)(numf)); ++i)
    if (!filled[i]) free_a.push(i);
  for (int i = (int)(numf); i < ((int)(n)); ++i)
    if (!filled[i]) free_b.push(i);
  for (int i = (int)(n); i < ((int)(clast)); ++i) {
    if (filled[i]) {
      int a;
      if (ws_to[by_idx[i]]) {
        a = free_a.front();
        free_a.pop();
      } else {
        a = free_b.front();
        free_b.pop();
      }
      ans.push_back(make_pair(by_idx[i], by_idx[a]));
      filled[i] = false;
      filled[a] = true;
    }
  }
  IO.writeInt(ans.size(), 0);
  IO.writeEndl();
  for (auto p : ans) {
    IO.writeString("move");
    IO.writeString(p.first);
    IO.writeString(p.second, 0);
    IO.writeEndl();
  }
  return 0;
}

