        adj[b].push_back(a);
    }

    vector<int> visited(n + 1, 0);
    vector<int> componentSize(n + 1, 0);

    function<void(int)> dfs = [&](int node) {
        visited[node] = 1;
        for (auto neighbor : adj[node]) {
            if (!visited[neighbor]) {
                dfs(neighbor);
            }
        }
        ++componentSize[node];
    };

