double expected_value(int n) {
    std::vector<double> probabilities(n + 1);
    probabilities[0] = 0.5; // Probability of getting a box lunch on the first day

    for (int i = 1; i <= n; ++i) {
        double new_probability = 0.5;
        for (int j = 1; j <= i; ++j) {
            new_probability *= 0.5;
        }
        probabilities[i] = new_probability;
    }

    double expected_value = 0.0;
    for (int i = 1; i <= n; ++i) {
        expected_value += probabilities[i];
    }

    return expected_value;
}

