int n, m, k;
vector<P> vil;
struct MSQ : public G{
	MSQ(){}
	vector<P> p;
	vector<S> s;
	int m, k;
	MSQ(int m, int k):m(m), k(k){
		REP(i, m) p.push_back(polar((R)1, 2*PI*i/m + PI*(R).5));
		REP(i, m) s.emplace_back(p[i], p[(i+k)%m]);
		Arrangement a(s);
		DualGraph dg(a.p);
		REP(i, a.g.size())REP(j, a.g[i].size()){
			int u = a.g[i][j].u;
			int v = a.g[i][j].v;
			if(u < v) dg.add_edge(u, v);
		}
		(G &)(*this) = dg.dual();
		reverse(this->begin(), this->end());
	}
	void copy(R r, P c, MSQ &msq)const {
		msq.resize(size());
		msq.p.resize(p.size());
		msq.s.resize(s.size());
		msq.m = m;
		msq.k = k;
		REP(i, size())   msq[i] = at(i)*r + c;
		REP(i, p.size()) msq.p[i] = p[i]*r + c;
		REP(i, s.size()) msq.s[i] = S(msq.p[i], msq.p[(i+k)%m]);
	}
	const S &segment(int i)const {
		return s[i];
	}
};
int convex_contains(const MSQ &msq, const P &g, const P &p) {
	const int n = msq.size();
	int a = 0, b = n;
	const P pg = p-g;
	while (a+1 < b) { // invariant: c is in fan g-P[a]-P[b]
		int c = (a + b) / 2;
		if (outp(msq[a]-g, pg) > 0 && outp(msq[c]-g, pg) < 0) b = c;
		else  a = c;
	}
	b %= n;
	if (outp(msq[a] - p, msq[b] - p) < -EPS) return 0;
	return 1;
}
bool check(const MSQ & temp, const R &r, const int &i, const int &j){
	MSQ msq;
	P gp = vil[i] - temp.segment(j)[0]*r;
	temp.copy(r, gp, msq);
	const S &l = msq.segment(j);
	vector<P> p;
	P b(0), u = l.dir();
	if(u < b) swap(b, u);
	RREP(i, n){
		S l2(vil[i], vil[i] + l.dir());
		int f = 0;
		P ll(INF, INF), rr(-INF, -INF);
		REP(j, m){
			const S &s = msq.segment(j);
			if(intersect(s, l2)){
				const P q = crosspoint(s, l2) - l2[0];
				p.push_back(q);
				ll = min(ll, q);
				rr = max(rr, q);
				f = 1;
			}
		}
		u = min(rr, u);
		b = max(ll, b);
		if(!f || u < b) return false;
	}
	FOR(q, p){
		if(*q < b || u < *q) continue;
		if([&](){
			REP(i, n) if(!convex_contains(msq, gp, vil[i] + *q)) return 0;
			return 1;
		}()) return true;
	}
	return false;
}

int main(){
	ios::sync_with_stdio(false);
	while(cin >> n >> m >> k, n){
		MSQ temp(m, k);
		vil = vector<P>(n);
		REP(i, n) cin >> vil[i];
		R best = 2000;
		REP(i, n)REP(j, m){
			if(!check(temp, best-EPS, i, j)) continue;
			R l=1., r = best;
			while(r-l>1e-6){
				R m = (l+r)*(R).5;
				if(check(temp, m, i, j)) r = m;
				else l = m;
			}
			best = r;
		}
		printf("%.10f\n", (double)best);
	}
	return 0;
}

