int countDistinctConcatenations(const std::string& s, const std::string& t) {
    std::unordered_set<std::string> result;

    // Iterate over all possible prefixes of s
    for (size_t i = 0; i <= s.length(); ++i) {
        std::string prefix = s.substr(0, i);

        // Iterate over all possible prefixes of t
        for (size_t j = 0; j <= t.length(); ++j) {
            std::string suffix = t.substr(0, j);

            // Check if the concatenation of prefix and suffix is unique
            if (result.find(prefix + suffix) == result.end()) {
                result.insert(prefix + suffix);
            }
        }
    }

    return result.size();
}

int main() {
    std::string s, t;
    std::cin >> s >> t;

