int mod = 998244353;

int countWays(int n, int k) {
    // Initialize a 2D vector to store the number of ways to place rooks
    vector<vector<int>> dp(n, vector<int>(n, 0));

    // Base case: there's only one way to place a single rook on a single cell
    dp[0][0] = 1;

    // Fill the dp table
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            // If the current cell is empty, there's only one way to place a rook here
            if (dp[i - 1][j] == 0) {
                dp[i][j] = 1;
            } else {
                // Check all possible positions for the rook
                for (int x = 0; x < n; ++x) {
                    if (i != x && j != x) {
                        // If the rook is not in the same row or column as the current cell,
                        // then there's only one way to place the rook here
                        dp[i][j] += dp[i - 1][x];
                    }
                }
            }
        }
    }

    // Return the number of ways to place the rooks
    return dp[n - 1][n - 1];
}

int main() {
