      int p1 = 1;
      for (int j = 1; j <= i; ++j) A[j][1][i] = --p1;
      for (int j = i; j; --j)
        if ((j - i) & 1)
          for (int k = 1; k <= i; ++k) A[j][0][k] = --p1;
        else
          for (int k = i; k; --k) A[j][0][k] = --p1;
      int p2 = A[i][i - 1][i - 1];
      for (int j = i - 1; j >= 2; --j) A[i][j][i] = ++p2;
      for (int j = 2; j < i; ++j)
        if (j & 1)
          for (int k = 1; k < i; ++k) A[k][j][i] = ++p2;
        else
          for (int k = i - 1; k; --k) A[k][j][i] = ++p2;
      for (int j = 1; j <= i; ++j)
