long long dp[262149][20];
long long kt[20];
long long s[20][20];
long long solve(long long mask, long long pr, long long n, long long t,
                long long u) {
  if (t == n) {
    return ((long long)0);
  }
  if (dp[mask][pr] != -1) {
    return dp[mask][pr];
  }
  dp[mask][pr] = 0;
  long long nmask;
  for (long long i = 0; i < u; i++) {
    if ((mask & (1 << i)) == 0) {
      nmask = mask + (1 << i);
      dp[mask][pr] =
          max(dp[mask][pr], s[pr][i] + kt[i] + solve(nmask, i, n, t + 1, u));
    }
  }
  return dp[mask][pr];
}
