        return true;
      else
        return false;
    }
  }
  if (cc[y[i]] > 0) {
    cc[y[i]]--;
    nz--;
    bool ok = check_less(i + 1, nz);
    cc[y[i]]++;
    nz++;
    return ok;
  } else
    return false;
}
bool check_more(int i, int nz) {
  if (i == MAXN) {
    if (nz > 0)
      return false;
    else
      return true;
  }
  for (int j = x[i] + 1; j < 10; j++) {
    if (cc[j] > 0) {
      if (MAXN - i >= nz)
        return true;
      else
        return false;
    }
  }
  if (cc[x[i]] > 0) {
    cc[x[i]]--;
    nz--;
    bool ok = check_more(i + 1, nz);
    cc[x[i]]++;
    nz++;
    return ok;
  } else
    return false;
}
bool check() {
  memcpy(cc, c, sizeof c);
  int nz = 0;
  for (int i = 0; i < 10; i++) nz += cc[i];
  for (int i = 0; i < MAXN; i++) {
    if (x[i] == y[i]) {
      if (cc[x[i]] == 0) return false;
      cc[x[i]]--;
      nz--;
    } else {
      for (int j = x[i] + 1; j < y[i]; j++) {
        if (cc[j] > 0) {
          if (MAXN - i >= nz)
            return true;
          else
            return false;
        }
      }
      if (cc[x[i]] > 0) {
        cc[x[i]]--;
        nz--;
        if (check_more(i + 1, nz)) return true;
        cc[x[i]]++;
        nz++;
      }
      if (cc[y[i]] > 0) {
        cc[y[i]]--;
        nz--;
        if (check_less(i + 1, nz)) return true;
        cc[y[i]]++;
        nz++;
      }
      return false;
    }
  }
  for (int i = 0; i < 10; i++)
    if (cc[i] > 0) return false;
  return true;
}
