  if (i == MAXN) {
    if (check())
      return 1;
    else
      return 0;
  } else {
    int r = 0;
    c[d]++;
    r += solve(i + 1, d);
    c[d]--;
    if (d < 9) r += solve(i, d + 1);
    return r;
  }
}
