std::pair<int, int> findMaxProperIrreducibleFraction(int n) {
    // Start with the smallest possible fraction
    int numerator = 1;
    int denominator = n;

    // Find the largest proper irreducible fraction
    while (true) {
        if (isProper(numerator, denominator)) {
            break;
        }
        ++numerator;
        --denominator;
    }

    return {numerator, denominator};
}

bool isProper(int numerator, int denominator) {
    // Check if the fraction is proper
    return numerator < denominator && gcd(numerator, denominator) == 1;
}

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int n;
    std::cin >> n;

    auto [numerator, denominator] = findMaxProperIrreducibleFraction(n);

    std::cout << numerator << " " << denominator << std::endl;

