int main()
{
	while(cin >> M >> N >> K >> D, (M||N||K||D))
	{
		vector<Edge> eg;

		for(int i=0; i<M; i++)
			cin >> cal[i];

		for(int i=0; i<D; i++)
		{
			string a,b;
			int s,d,c;
			cin >> a >> b >> c;
			s=toNum(a); d=toNum(b);

			eg.pb(Edge(s,d,c*K));
			eg.pb(Edge(d,s,c*K));
		}

		int dist[300][(1<<6)];
		for(int i=0; i<(1<<M); i++)
		for(int j=0; j<M+N+2; j++)
			dist[j][i]=INF;

		dist[HE][0]=0;

		while(1)
		{
			bool update=false;
			for(int i=0; i<eg.size(); i++)
			for(int j=0; j<(1<<M); j++)
			{
				Edge e=eg[i];
				if(dist[e.u][j]==INF) continue;
				if(e.v<M)
