					if(dist[e.u][j]+e.c-cal[e.v] < dist[e.v][j|(1<<e.v)])
					{
						update=true;
						dist[e.v][j|(1<<e.v)]=dist[e.u][j]+e.c-cal[e.v];
					}
				}
				else
				{
					if(dist[e.u][j]+e.c < dist[e.v][j])
					{
						update=true;
						dist[e.v][j]=dist[e.u][j]+e.c;
					}
				}
			}

			if(!update) break;
		}

		int ans=INF;
		for(int i=0; i<(1<<M); i++)
			ans=min(ans, dist[CH][i]);

		cout << ans << endl;
	}
}

