vec ternarysearch(vec& p0, vec& p1, vec& p2, long double tg, long double tw){
    //???p0??????p2??????????????????p2p3?????????????????£?????????????????§????????????????????????????????????
    long double left=1.0/3.0,right=2.0/3.0;
    long double t,t1,t2;
    vec P1,P2;
    while(true){
        P1=p1*(1-left)+p2*left;
