        t1=(p0-P1).norm()*tw+(p2-P1).norm()*tg;
        t2=(p0-P2).norm()*tw+(p2-P2).norm()*tg;
        if(abs(t1-t2)<1e-11){
            t=(left+right)/2;
            if(1.0-t<1e-8){
