using P = pair<int, int>;
bool ok(vector<P> v) {
    for (auto &p: v) {
        if (p.first > p.second) {
            swap(p.first, p.second);
        }
    }
    sort(begin(v), end(v));
    vector<P> st;
    for (auto p: v) {
        while (st.size() && st.back().second < p.first) {
            st.pop_back();
        }
        if (st.size() && st.back().second < p.second) {
            return false;
        }
        st.push_back(p);
    }
    return true;
}

