int main() {
  // 最短の矢の長さ（or-1）
  // 矢の長さをxとすると
  // l>=N-(x*M)を満たす最低のxが答え
  // N*l/M<=x
  // しかし当然ながら扇風機の範囲がかぶるところが存在する
  // xを順に伸ばして言ってDPに損失を保存していく
  int N,M;cin>>N>>M;
  vector<int> ms(M);
  REP(i,M) cin>>ms[i];

  // 損失にならない場はtrue
  bitset<100000> bs;
  REP(i,M) bs.set(N-1-(ms[i]-1));

  // 長さがiの時の損失の数をdp[i-1]とする
  vector<ll> dp(N,0);
  dp[0] = N-M;

  // 余計なzeroの数
  int red = 100000 - N;

  FOR(n,1,N) {
    bs |= bs>>1;
    dp[n] = 100000 - bs.count()-red;
  }
  // DUMP(dp);

  int Q;cin>>Q;

  // 逆順にして、l+1のlower_bound-begin-1=idxとしたとき、N-idxが答え
  reverse(ALL(dp));

  REP(i,Q) {
    int l;cin>>l;
    if (dp[0]>l) {
      OUT(-1);
    } else {
      ll idx = lower_bound(ALL(dp),l+1)-dp.begin()-1;
      OUT(N-idx);
    }
  }

  return 0;
}

