long long binpow(long long a, long long b) {
  long long res = 1;
  while (b > 0) {
    if (b & 1) res = (res * a) % mod;
    a = (a * a) % mod;
    b >>= 1;
  }
  return res % mod;
}
int dfs(int src) {
  stack<int> st;
  int cnt = 0;
  st.push(src);
  vis[src] = 1;
  cnt++;
  while (!st.empty()) {
    int x = st.top();
    st.pop();
    if (!vis[x]) {
      cnt++;
      vis[x] = 1;
    }
    for (int i = 0; i < v[x].size(); i++) {
      if (vis[v[x][i]] == 0) st.push(v[x][i]);
    }
  }
  return cnt;
}
