    for (int i = 1; i < sz; i++) psum[i] += psum[i - 1];
    int i = 1, j = K;
    ans = psum[sz - 1] - psum[K - 1];
    while (j < sz) {
      long long temp = psum[sz - 1] - psum[j];
      temp += psum[i - 1];
      ans = min(ans, temp);
      i++;
      j++;
    }
  }
  cout << ans << "\n";
}
