void color(int u, int p, int cur, int step, bool diameter = true) {
  cur += step;
  if (cur > k)
    cur -= k;
  else if (cur <= 0)
    cur += k;
  res[u] = cur;
  int U = 0;
  for (int i = 0; i < (int)a[u].size(); i++) {
    int v = a[u][i];
    if (v == p) continue;
    if (diameter) {
      if (U == 0 && h[v] == h[root]) {
        U = v;
        continue;
      }
      int len = h[v] - d[v] + 1;
      if (k > 2 && len + d[u] >= k && len + h[root] - d[u] + 1 >= k) {
        cout << "No";
        exit(0);
      } else if (len + d[u] >= k)
        color(v, u, cur, step, false);
      else
        color(v, u, cur, -step, false);
    } else
      color(v, u, cur, step, false);
  }
  if (U) color(U, u, cur, step);
}
