int main() {
    int n;
    cin >> n;
    vector<vector<int>> grid(n, vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            cin >> grid[i][j];
        }
    }

    int mod = 998244353;
    vector<vector<int>> dp(n, vector<int>(n, 0));

    // Base case: there's only one way to reach the first row
    for (int i = 0; i < n; ++i) {
        dp[0][i] = 1;
    }

    // Fill the DP table
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (grid[i][j] > 0) {
                dp[i][j] = (dp[i - 1][j] + dp[i - 1][j + 1]) % mod;
            } else if (grid[i][j] < 0) {
                dp[i][j] = (dp[i - 1][j] - dp[i - 1][j - 1]) % mod;
            }
        }
    }

    // The number of paths from the first row to the last row
    int result = 0;
    for (int i = 0; i < n; ++i) {
        result = (result + dp[n - 1][i]) % mod;
    }

    cout << result << endl;
    return 0;
}

