using namespace std;

int maxIndependentSet(vector<int>& a) {
    int n = a.size();
    vector<vector<int>> G(n, vector<int>());

    // Build the graph
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] > a[i + 1]) {
            G[i].push_back(a[i + 1]);
            G[i + 1].push_back(a[i]);
        }
    }

    // Find the maximum independent set
    vector<bool> visited(n, false);
    int max_independent_set_size = 0;
    for (int i = 0; i < n; ++i) {
        if (!visited[i]) {
            int current_size = 1;
            queue<int> q;
            q.push(i);
            visited[i] = true;

            while (!q.empty()) {
                int current = q.front();
                q.pop();
                current_size++;

                for (int neighbor : G[current]) {
                    if (!visited[neighbor]) {
                        q.push(neighbor);
                        visited[neighbor] = true;
                    }
                }
            }

            if (current_size > max_independent_set_size) {
                max_independent_set_size = current_size;
            }
        }
    }

    return max_independent_set_size;
}

