long long C[M], x, y, tar[N], dep[N], in[M];
int fir[N], ne[M], to[M], cnt = 1, fa[N], fan[N];
void add(int x, int y) {
  ne[++cnt] = fir[x];
  fir[x] = cnt;
  to[cnt] = y;
}
void link(int x, int y) {
  add(x, y);
  add(y, x);
}
bool vis[N];
int dfs(int x, int f) {
  int res = 0;
  fa[x] = f;
  dep[x] = dep[f] + 1;
  vis[x] = 1;
  for (int i = fir[x]; i; i = ne[i]) {
    int V = to[i];
    if (vis[V]) {
      if (V != f) {
        if ((dep[V] + dep[x]) & 1)
          ;
        else
          res = i;
      }
      continue;
    }
    int cur = 0;
    if (cur = dfs(V, x)) res = cur;
    if (tar[V]) {
      tar[x] -= tar[V];
      C[i] += tar[V];
      C[i ^ 1] += tar[V];
      tar[V] = 0;
    }
    fan[V] = i;
  }
  return res;
}
void Bush(int x) {
  while (fa[x]) {
    tar[fa[x]] -= tar[x];
    C[fan[x]] += tar[x];
    C[fan[x] ^ 1] += tar[x];
    tar[x] = 0;
    x = fa[x];
  }
}
