  for (int i = 1; i <= n; ++i) scanf("%lld", &tar[i]);
  for (int i = 1; i <= m; ++i) scanf("%d%d", &x, &y), link(x, y);
  for (int i = 1; i <= n; ++i) {
    if (!vis[i]) {
      int cur = dfs(i, 0), a;
      if ((tar[i]) & 1 || (!cur && tar[i])) return puts("NO") * 0;
      a = (dep[to[cur]] & 1);
      C[cur] = C[cur ^ 1] += tar[i] / 2 * (a ? 1 : (-1));
      tar[to[cur ^ 1]] = tar[to[cur]] = -tar[i] / 2 * (a ? 1 : (-1));
      Bush(to[cur]);
      Bush(to[cur ^ 1]);
    }
