#include <iostream>
#include <vector>
#include <algorithm>

bool canSort(const std::vector<int>& arr) {
    int n = arr.size();
    std::vector<std::stack<int>> stacks(n);

    // Build stacks
    for (int i = 0; i < n; ++i) {
        stacks[i].push(arr[i]);
    }

    // Sort stacks based on height difference
    std::sort(stacks.begin(), stacks.end(), [](const std::stack<int>& s1, const std::stack<int>& s2) {
        return std::abs(s1.top() - s2.top()) > 2;
    });

    // Find the tallest stack
    int maxHeight = 0;
    for (const auto& stack : stacks) {
        maxHeight = std::max(maxHeight, stack.top());
    }

    // Output the result
    std::vector<int> result(maxHeight + 1);
    int index = 0;
    for (const auto& stack : stacks) {
        while (!stack.empty() && stack.top() == maxHeight) {
            result[index++] = stack.top();
            stack.pop();
        }
    }

    // Print the result
    for (int i = 0; i <= maxHeight; ++i) {
        std::cout << result[i];
        if (i < maxHeight) {
            std::cout << " ";
        }
    }
    std::cout << std::endl;

    return true;
}

