	for(int i=1,a;i<=n;i++){
		scanf("%d",&a);
		int t = query(1,0,MA,std::max(0,a-k),std::min(MA,a+k))+1;
		ans = std::max(ans,t);
		modify(1,0,MA,a,t);
	}
	printf("%d\n",ans);
}

