int f(int l,int r){
  if(l+1==r){
    return s[l]-'0';
  }
  if(s[l]=='-'){
    return 2-f(l+1,r);
  }
  if(s[l]=='('){
    int level=-1;
    repl(i,l,r){
      if(s[i]=='(')level++;
      else if(s[i]==')')level--;
      if(level==0&&s[i]=='+'){
        return max(f(l+1,i),f(i+1,r-1));
      }
      if(level==0&&s[i]=='*'){
        return min(f(l+1,i),f(i+1,r-1));
      }
    }
  }
  return -1;
}

