#include <iostream>
#include <string>
#include <vector>

int countValidTriples(const std::string& formula) {
    int count = 0;
    std::vector<std::vector<int>> truthTable(3, std::vector<int>(3, 0));

    // Parse the formula into its components
    for (char ch : formula) {
        if (ch == '-') {
            continue; // Skip the unary operator
        }
        if (ch >= '0' && ch <= '9') {
            truthTable[0][ch - '0'] = 1; // True for 0, 1, 2
        } else if (ch == 'P' || ch == 'Q' || ch == 'R') {
            truthTable[ch - 'P'][ch - 'Q'] = 1; // True for P, Q, R
        } else if (ch == '-') {
            truthTable[1][ch - 'P'] = 1; // True for -P
        } else if (ch == '*') {
            truthTable[2][ch - 'P'] = 1; // True for *P
        } else if (ch == '+') {
            truthTable[2][ch - 'P'] = 1; // True for +P
        } else {
            // Invalid character, skip it
            continue;
        }
    }

    // Check all possible combinations of P, Q, R
    for (int p = 0; p < 3; ++p) {
        for (int q = 0; q < 3; ++q) {
            for (int r = 0; r < 3; ++r) {
                if (truthTable[p][q] == 1 && truthTable[q][r] == 1 && truthTable[r][p] == 1) {
                    ++count;
                }
            }
        }
    }

    return count;
}

int main() {
    std::string input;
    while (std::getline(std::cin, input)) {
        if (input == ".") {
            break;
        }
        std::cout << countValidTriples(input) << std::endl;
    }
    return 0;
}

