				memcpy(t, arr, sizeof t);
				for (int j=0; j<size; ++j) {
					for (int k=0; k<size; ++k) {
						assert(r+j < 15 && c+k < 15);
						assert(r+k < 15 && c+size-1-j < 15);
						arr[r+j][c+k] = t[r+k][c+size-1-j];
					}
