#include <iostream>
using namespace std;

int main() {
    int w, h;
    cin >> w >> h;

    // Read the grid
    char grid[w][h];
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            cin >> grid[i][j];
        }
    }

    // Function to check if a cell is surrounded by black or white stakes
    bool is_surrounded(int i, int j, char grid[][h]) {
        int count_black = 0;
        int count_white = 0;

        // Check all four directions
        for (int di = -1; di <= 1; ++di) {
            for (int dj = -1; dj <= 1; ++dj) {
                if (di == 0 && dj == 0) continue; // Skip the center cell
                int ni = i + di;
                int nj = j + dj;

                // Check if the cell is within bounds and if it's a black or white stake
                if (ni >= 0 && ni < w && nj >= 0 && nj < h && grid[ni][nj] == grid[i][j]) {
                    if (grid[ni][nj] == 'B') {
                        ++count_black;
                    } else {
                        ++count_white;
                    }
                }
            }
        }

        // If there are more black or white stakes than black or white stakes in the current cell, return false
        return count_black > count_white;
    }

    // Calculate the area of land surrounded by black and white stakes
    int black_area = 0, white_area = 0;
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            if (is_surrounded(i, j, grid)) {
                black_area += (h - j);
                white_area += (w - i);
            }
        }
    }

    // Output the results
    cout << black_area << " " << white_area << endl;

    return 0;
}

