std::string restoreParenthesis(int n, std::vector<int>& p) {
    // Base case: if there's only one element, return it as a single parenthesis
    if (n == 1) {
        return "(" + p[0] + ")";
    }

    // Create a vector to store the result
    std::vector<std::string> result;

    // Iterate over each permutation
    for (int i = 0; i < (1 << n); ++i) {
        int num = 0;
        // Count the number of '1's in the permutation
        for (int j = 0; j < n; ++j) {
            if ((i >> j) & 1) {
                num++;
            }
        }

        // If the number of '1's matches the number of elements in the permutation
        if (num == n) {
            // Construct the current permutation
            std::string current;
            for (int j = 0; j < n; ++j) {
                if ((i >> j) & 1) {
                    current += p[j];
                }
            }
            // Add the current permutation to the result
            result.push_back(current);
        }
    }

    // If no valid permutation was found, return ":("
    if (result.empty()) {
        return ":(";
    }

    // Join the result strings into a single string and return
    return result[0];
}

