ll mod_pow(ll a , ll n , ll mod){
    if(n == 0){
        return 1;
    }
    ll res = mod_pow((a*a)%mod , n/2 , mod);
    if(n % 2){
        res = (res*a)%mod;
    }
    return res;
}
ll mod_inv(ll x , ll mod){
    return mod_pow(x , mod - 2 , mod);
}
ll nCr(ll n , ll r , ll mod){
    return ((fact[n]*mod_inv(fact[r] , mod) % mod)* (mod_inv(fact[n - r] , mod) % mod))%mod;
