  double k = (x - b.x) / (c.x - b.x);
  return point(b.x + (c.x - b.x) * k, b.y + (c.y - b.y) * k);
}
int operator<(const line& a, const line& b) {
  double l = max(d[a.s].x, d[b.s].x), r = min(d[a.t].x, d[b.t].x);
  double x = (l + r) * 0.5;
  point s1 = get(d[a.s], d[a.t], x), s2 = get(d[b.s], d[b.t], x);
  if (s1.y != s2.y)
    return s1.y < s2.y;
