  hh[S] = 1;
  while (!q.empty()) {
    u = q.front();
    q.pop();
    hh[u] = 0;
    for (i = head[u]; i; i = nxt[i]) {
      v = t[i];
      if (dis[v] > dis[u] + c[i]) {
        dis[v] = dis[u] + c[i];
        if (!hh[v]) {
          hh[v] = 1;
          q.push(v);
        }
      }
    }
  }
  return dis[T];
}
void update(int now) {
  set<line>::iterator ii, it = st.find(l[p[now].num]);
  if (it == st.end()) return;
  if (it->type == -1) {
    ii = it;
    ++ii;
    while (same(p[now].x, *ii, *it) && ii->type == it->type) {
      ++ii;
      if (ii == st.end()) return;
    }
    if (ii == st.end()) return;
  }
  if (it->type == 1) {
    if (it == st.begin()) return;
    ii = it;
    --ii;
    while (same(p[now].x, *ii, *it) && ii->type == it->type) {
      if (ii == st.begin()) return;
      --ii;
    }
    swap(ii, it);
  }
  if (it->type == ii->type) return;
  add(p[now].x, *ii, *it);
}
