    if (d[i].x != d[j].x) {
      if (chaji(d[i], d[j], TOP) >= 0)
        l[i].type = -1;
      else
        l[i].type = 1;
      if (d[l[i].s].x > d[l[i].t].x) swap(l[i].s, l[i].t);
      p[++num] = accident((int)d[l[i].s].x, i, 1);
      p[++num] = accident((int)d[l[i].t].x, i, -1);
    }
  }
  set<line>::iterator it;
