    }
    j = now;
    while (j <= num && p[j].x == p[now].x) update(j), ++j;
    j = now;
    while (j <= num && p[j].x == p[now].x) {
      if (p[j].flag == -1) {
        st.erase(l[p[j].num]);
      }
      ++j;
    }
    now = j;
  }
