using namespace std;
struct T {
  long long sum;
  int len;
  long long sol;
};
T unite(T a, T b) {
  long long sum = a.sum + b.sum;
  int len = a.len + b.len;
  long long sol = a.sol + b.sol + b.sum * a.len - a.sum * b.len;
  return {sum, len, sol};
}
const int N = (int)1e5 + 7;
