T aint[4 * N * 3];
void del(int v, int tl, int tr, int pos) {
  if (tr < pos || pos < tl) {
    return;
  }
  if (tl == tr) {
    aint[v] = {0, 0, 0};
  } else {
    int tm = (tl + tr) / 2;
    del(2 * v, tl, tm, pos);
    del(2 * v + 1, tm + 1, tr, pos);
    aint[v] = unite(aint[2 * v], aint[2 * v + 1]);
  }
}
void make(int v, int tl, int tr, int pos, long long x) {
  if (tr < pos || pos < tl) {
    return;
  }
  if (tl == tr) {
    aint[v] = {x, 1, 0};
  } else {
    int tm = (tl + tr) / 2;
    make(2 * v, tl, tm, pos, x);
    make(2 * v + 1, tm + 1, tr, pos, x);
    aint[v] = unite(aint[2 * v], aint[2 * v + 1]);
  }
}
T get(int v, int tl, int tr, int l, int r) {
  if (tr < l || r < tl) {
    return {0, 0, 0};
  }
  if (l <= tl && tr <= r) {
    return aint[v];
  } else {
    int tm = (tl + tr) / 2;
    return unite(get(2 * v, tl, tm, l, r), get(2 * v + 1, tm + 1, tr, l, r));
  }
}
