  lines.push_back(1);
  stack<int> s;
  s.push(1);
  C[1] = 0;
  for (int i = 2, id = 0; i <= N; i++) {
    int di = s.top();
    while (id < intervals.size() && intervals[id].second < A[i]) {
      id++;
    }
