int minBoxSize(int n, int k, std::vector<int>& s) {
    // Sort the cowbell sizes
    std::sort(s.begin(), s.end());

    // Initialize variables
    int total = 0;
    int currentBoxSize = 0;

    // Iterate through the sorted cowbell sizes
    for (int size : s) {
        // Add the current size to the total
        total += size;

        // If the total exceeds the current box size, increment the box size
        if (total > currentBoxSize) {
            currentBoxSize++;
        }
    }

    return currentBoxSize;
}

