std::string restoreString(int k, int n, std::vector<std::string>& s) {
    // Sort the strings based on their lengths
    std::sort(s.begin(), s.end(), [](const std::string& a, const std::string& b) {
        return a.length() < b.length();
    });

    // Iterate through the sorted strings
    for (int i = 0; i < k; ++i) {
        // Find the index of the first occurrence of the current string
        int j = 0;
        while (j < n && s[i][j] != s[i][j + 1]) {
            ++j;
        }

        // If no such index is found, return -1
        if (j == n) {
            return -1;
        }

        // Swap the characters at the found index with the next character
        std::swap(s[i][j], s[i][j + 1]);
    }

    // Return the modified string
    return s[0];
}

