int get_min(vector< vector<int> > & RMQ, int l, int r) {
	int ret = OVER9000;
	for(int i = 0; i < 19; i++) if(((r-l)>>i)&1) {
		ret = min(ret, RMQ[i][l]);
		l += 1<<i;
		if(l == r) break;
	}
	return ret;
}

int get_max(vector< vector<int> > & RMQ, int l, int r) {
	int ret = -1;
	for(int i = 0; i < 19; i++) if(((r-l)>>i)&1) {
		ret = max(ret, RMQ[i][l]);
		l += 1<<i;
		if(l == r) break;
	}
	return ret;
}

