int maxArea(int n, int arr[]) {
    int maxArea = 0;
    int left = 0;
    int right = n - 1;

    while (left < right) {
        int width = right - left + 1;
        int height = min(arr[left], arr[right]);

        maxArea = max(maxArea, width * height);

        if (arr[left] < arr[right]) {
            left++;
        } else {
            right--;
        }
    }

    return maxArea;
}

