int minCost(int n, std::vector<std::vector<int>>& walls, int m, std::vector<std::vector<int>>& types) {
    // Sort the walls by length and width
    std::sort(walls.begin(), walls.end());

    // Calculate the total length of the walls
    int totalLength = 0;
    for (const auto& wall : walls) {
        totalLength += wall[0] + wall[1];
    }

    // Initialize variables to store the minimum cost and the number of rolls needed
    int minCost = INT_MAX;
    int numRolls = 0;

    // Iterate through the types of wallpaper
    for (const auto& type : types) {
        int length = type[0], width = type[1], price = type[2];

        // Calculate the number of rolls needed for the current type
        int rollsNeeded = totalLength / (length * width);

        // Update the minimum cost if the current type costs less
        if (price < minCost) {
            minCost = price;
            numRolls = rollsNeeded;
        }
    }

    return minCost;
}

