double calculateDistance(const std::vector<std::pair<int, int>>& polyline, int x_n, int y_n, int H) {
    double totalDistance = 0;
    for (int i = 0; i < polyline.size(); ++i) {
        int x1 = polyline[i].first;
        int y1 = polyline[i].second;
        int x2 = polyline[(i + 1) % polyline.size()].first;
        int y2 = polyline[(i + 1) % polyline.size()].second;

        // Calculate the distance between the current vertex and the eye
        double distance = std::sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));

        // Check if the distance is within the eye height
        if (distance <= H) {
            // Calculate the distance from the eye to the current vertex
            double distanceToEye = std::sqrt((x2 - x_n) * (x2 - x_n) + (y2 - y_n) * (y2 - y_n));

            // Add the distance to the total distance
            totalDistance += distanceToEye;
        }
    }

    return totalDistance;
}

