void doit() {
  int dp = 1, cp = l, tp;
  while (cp >= l && cp <= r) {
    if (tmp[cp] == '<' || tmp[cp] == '>') {
      if (tmp[cp] == '<') {
        dp = -1;
        tp = cp - 1;
        while (tp >= l && vis[tp]) tp--;
        if (tp < l) break;
        if (tmp[tp] == '<' || tmp[tp] == '>') vis[cp] = true;
        cp = tp;
