      } else {
        dp = 1;
        tp = cp + 1;
        while (tp <= r && vis[tp]) tp++;
        if (tp > r) break;
        if (tmp[tp] == '<' || tmp[tp] == '>') vis[cp] = true;
        cp = tp;
        continue;
      }
