double calculateProbability(int a, int b, int c, int d) {
    // Calculate the probability of SmallR shooting in the target first
    double smallRProbability = std::pow(a / (a + b), 2);

    // Calculate the probability of Zanoes shooting in the target first
    double zanoesProbability = std::pow(b / (b + c), 2);

    // Calculate the probability that SmallR wins the match
    double probability = smallRProbability * zanoesProbability;

    // Return the probability rounded to 6 decimal places
    return std::round(probability * 100000.0) / 100000.0;
}

